INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Million Dollar Chicken Casserole','million-dollar-chicken-casserole','This rich and creamy chicken casserole lives up to its name with layers of tender chicken, cream cheese, and a buttery cracker topping. It is the ultimate comfort food dish that feeds a crowd and tastes like a million dollars.','A creamy and indulgent baked chicken casserole topped with buttery crushed crackers.','American','Easy',15,45,60,8,520,34,22,34,1,'[{"amount":3,"unit":"cups","item":"shredded rotisserie chicken","group":"Filling"},{"amount":8,"unit":"oz","item":"cream cheese softened","group":"Filling"},{"amount":1,"unit":"cup","item":"sour cream","group":"Filling"},{"amount":1,"unit":"can","item":"cream of chicken soup","group":"Filling"},{"amount":1,"unit":"cup","item":"shredded cheddar cheese","group":"Filling"},{"amount":1,"unit":"tsp","item":"garlic powder","group":"Seasoning"},{"amount":2,"unit":"cups","item":"crushed buttery crackers","group":"Topping"},{"amount":4,"unit":"tbsp","item":"unsalted butter melted","group":"Topping"}]','[{"title":"Preheat and Prepare Dish","text":"Preheat your oven to 350 degrees F. Lightly grease a 9x13 inch baking dish with cooking spray and set aside.","timer":0},{"title":"Mix the Creamy Filling","text":"In a large bowl combine the softened cream cheese, sour cream, cream of chicken soup, shredded cheddar cheese, and garlic powder. Stir until smooth and well blended.","timer":0},{"title":"Add the Chicken","text":"Fold the shredded rotisserie chicken into the creamy mixture until every piece is well coated. Spread the mixture evenly into the prepared baking dish.","timer":0},{"title":"Add the Cracker Topping","text":"In a small bowl combine the crushed buttery crackers with the melted butter and toss to coat. Sprinkle the cracker mixture evenly over the top of the chicken filling.","timer":0},{"title":"Bake Until Golden","text":"Bake uncovered in the preheated oven for 40 to 45 minutes until the topping is golden brown and the filling is hot and bubbling around the edges. Let rest for 5 minutes before serving.","timer":2700}]','[{"original":"sour cream","swap":"plain Greek yogurt"},{"original":"buttery crackers","swap":"panko breadcrumbs mixed with butter"},{"original":"cream of chicken soup","swap":"homemade bechamel sauce"}]','["Not softening the cream cheese before mixing which leads to a lumpy filling","Skipping the resting time after baking which causes the casserole to fall apart when served","Using cold chicken straight from the fridge which results in uneven heating throughout the dish"]','["casserole","comfort food","chicken","creamy","baked","family dinner","crowd pleaser","weeknight"]','["Gluten-Free Optional"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Marry Me Chicken','marry-me-chicken','Marry Me Chicken is a swoon-worthy skillet dish featuring pan-seared chicken breasts in a luscious sun-dried tomato cream sauce that is so good it just might lead to a proposal. The combination of garlic, parmesan, and fresh herbs creates an unforgettable restaurant-quality meal at home.','Tender pan-seared chicken in a rich sun-dried tomato and parmesan cream sauce.','Italian-American','Medium',10,30,40,4,480,42,10,30,1,'[{"amount":4,"unit":"pieces","item":"boneless skinless chicken breasts","group":"Chicken"},{"amount":0.5,"unit":"cup","item":"sun-dried tomatoes in oil drained","group":"Sauce"},{"amount":1,"unit":"cup","item":"heavy cream","group":"Sauce"},{"amount":0.75,"unit":"cup","item":"chicken broth","group":"Sauce"},{"amount":0.5,"unit":"cup","item":"grated parmesan cheese","group":"Sauce"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"Sauce"},{"amount":1,"unit":"tsp","item":"dried Italian seasoning","group":"Seasoning"},{"amount":2,"unit":"tbsp","item":"olive oil","group":"Cooking"}]','[{"title":"Sear the Chicken","text":"Season the chicken breasts generously on both sides with salt, pepper, and half of the Italian seasoning. Heat olive oil in a large oven-safe skillet over medium-high heat and sear the chicken for 4 to 5 minutes per side until golden brown. Remove chicken and set aside.","timer":600},{"title":"Saute Garlic and Tomatoes","text":"In the same skillet reduce heat to medium. Add the minced garlic and sun-dried tomatoes and cook for 1 to 2 minutes stirring constantly until the garlic is fragrant and lightly golden.","timer":120},{"title":"Build the Cream Sauce","text":"Pour in the chicken broth and scrape up any browned bits from the bottom of the pan. Add the heavy cream and remaining Italian seasoning and stir to combine. Bring the sauce to a gentle simmer over medium heat.","timer":180},{"title":"Add Parmesan and Return Chicken","text":"Stir in the grated parmesan cheese until melted and the sauce is smooth. Nestle the seared chicken breasts back into the skillet and spoon sauce over the tops.","timer":0},{"title":"Finish in the Oven","text":"Transfer the skillet to an oven preheated to 375 degrees F and bake for 15 to 18 minutes until the chicken is cooked through and reaches an internal temperature of 165 degrees F. Garnish with fresh basil before serving.","timer":1080}]','[{"original":"heavy cream","swap":"full-fat coconut cream for a dairy-free version"},{"original":"sun-dried tomatoes","swap":"roasted red peppers"},{"original":"chicken breasts","swap":"bone-in chicken thighs for more flavor"}]','["Not patting the chicken dry before searing which prevents a proper golden crust from forming","Adding parmesan to a boiling sauce which causes it to clump instead of melt smoothly","Overcrowding the pan when searing which causes the chicken to steam rather than brown"]','["romantic dinner","chicken","creamy","sun-dried tomato","parmesan","Italian","date night","skillet"]','["Gluten-Free","Low-Carb"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Dirty Spaghetti','dirty-spaghetti','Dirty Spaghetti is a bold and flavor-packed pasta dish loaded with Italian sausage, crispy bacon, and a savory tomato sauce that earns its name from the deep rich color and intense flavors. Every bite is layered with smoky, spicy, and hearty goodness that makes it impossible to stop eating.','A hearty and bold spaghetti loaded with Italian sausage, bacon, and a rich tomato sauce.','Italian-American','Medium',10,35,45,6,610,30,58,28,4,'[{"amount":1,"unit":"lb","item":"spaghetti","group":"Pasta"},{"amount":0.5,"unit":"lb","item":"Italian sausage casings removed","group":"Meat"},{"amount":6,"unit":"slices","item":"bacon chopped","group":"Meat"},{"amount":1,"unit":"can","item":"crushed tomatoes 28 oz","group":"Sauce"},{"amount":1,"unit":"medium","item":"yellow onion diced","group":"Aromatics"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"Aromatics"},{"amount":1,"unit":"tsp","item":"crushed red pepper flakes","group":"Seasoning"},{"amount":0.5,"unit":"cup","item":"grated pecorino romano cheese","group":"Finishing"}]','[{"title":"Cook the Bacon and Sausage","text":"In a large deep skillet or Dutch oven over medium heat cook the chopped bacon until crispy. Remove bacon with a slotted spoon and set aside leaving the fat in the pan. Add the Italian sausage to the same pan and cook breaking it apart until browned and cooked through. Remove and set aside with the bacon.","timer":600},{"title":"Saute the Aromatics","text":"In the same pan with the remaining drippings add the diced onion and cook over medium heat for 4 to 5 minutes until softened and translucent. Add the minced garlic and red pepper flakes and cook for 1 more minute until fragrant.","timer":360},{"title":"Build and Simmer the Sauce","text":"Pour the crushed tomatoes into the pan and stir to combine with the onion mixture. Return the cooked bacon and sausage to the pan. Season with salt and black pepper and let the sauce simmer over low heat for 20 minutes stirring occasionally to develop deep flavor.","timer":1200},{"title":"Cook the Spaghetti","text":"While the sauce simmers bring a large pot of heavily salted water to a boil. Cook the spaghetti according to package directions until al dente. Reserve 1 cup of pasta cooking water before draining.","timer":600},{"title":"Combine and Serve","text":"Add the drained spaghetti directly to the sauce and toss vigorously to coat all the pasta. Add a splash of reserved pasta water to loosen the sauce if needed. Serve immediately topped with grated pecorino romano cheese.","timer":0}]','[{"original":"Italian sausage","swap":"ground beef or ground turkey"},{"original":"pecorino romano","swap":"grated parmesan cheese"},{"original":"bacon","swap":"pancetta for a more traditional Italian flavor"}]','["Not reserving pasta water before draining which makes it impossible to adjust sauce consistency","Rinsing the cooked pasta which washes away the starch needed for the sauce to cling properly","Cooking the sauce for too short a time which results in a thin and underdeveloped flavor"]','["pasta","spaghetti","sausage","bacon","tomato sauce","comfort food","weeknight","hearty"]','["Dairy-Free Optional"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Big Mac Smash Tacos','big-mac-smash-tacos','These Big Mac Smash Tacos combine the iconic flavors of a classic burger with the fun format of a street taco. Each bite delivers juicy smashed beef, special sauce, and all the classic toppings wrapped in a crispy tortilla shell.','Smashed beef patties in tortillas with special sauce and classic Big Mac toppings.','American','Easy',15,15,30,4,520,28,34,30,2,'[{"amount":1,"unit":"lb","item":"80/20 ground beef","group":"Protein"},{"amount":8,"unit":"count","item":"small flour tortillas","group":"Base"},{"amount":0.5,"unit":"cup","item":"mayonnaise","group":"Sauce"},{"amount":2,"unit":"tbsp","item":"yellow mustard","group":"Sauce"},{"amount":1,"unit":"cup","item":"shredded iceberg lettuce","group":"Toppings"},{"amount":4,"unit":"slices","item":"American cheese","group":"Toppings"},{"amount":0.5,"unit":"cup","item":"diced white onion","group":"Toppings"},{"amount":0.25,"unit":"cup","item":"dill pickle slices","group":"Toppings"}]','[{"title":"Make the Special Sauce","text":"In a small bowl combine mayonnaise, yellow mustard, and a pinch of garlic powder. Stir until smooth and set aside in the refrigerator.","timer":0},{"title":"Portion the Beef","text":"Divide the ground beef into 8 equal balls, each about 2 ounces. Season each ball generously with salt and black pepper on all sides.","timer":0},{"title":"Smash the Beef onto Tortillas","text":"Heat a cast iron skillet over medium-high heat. Place a beef ball onto a tortilla and use a spatula to smash it flat directly onto the dry skillet. Cook for 2 to 3 minutes until the edges are crispy and browned.","timer":180},{"title":"Add Cheese and Flip","text":"Place a slice of American cheese on the beef, then fold the tortilla over to form a taco shape. Press gently and cook for another 1 minute until the tortilla is golden and the cheese has melted.","timer":60},{"title":"Assemble and Serve","text":"Open each taco and spread special sauce on the inside. Top with shredded iceberg lettuce, diced white onion, and dill pickle slices. Serve immediately while hot and crispy.","timer":0}]','[{"original":"flour tortillas","swap":"corn tortillas for a gluten free option"},{"original":"mayonnaise","swap":"Greek yogurt for a lighter sauce base"},{"original":"American cheese","swap":"cheddar cheese slices for a sharper flavor"}]','["Using lean ground beef which results in dry and less flavorful smash patties","Not preheating the skillet enough causing the beef to steam rather than sear","Overfilling the taco with toppings which makes it impossible to fold and eat cleanly"]','["smash tacos","burger tacos","big mac","quick dinner","ground beef","american"]','["dairy-free adaptable"]','Dinner','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Cottage Cheese Flatbread','cottage-cheese-flatbread','This high-protein cottage cheese flatbread is a simple two-ingredient base that bakes up into a sturdy and delicious wrap or pizza-style crust. It is packed with protein and works perfectly as a low-carb alternative to traditional bread.','A simple high-protein flatbread made from blended cottage cheese and eggs.','American','Easy',10,30,40,2,220,24,6,10,1,'[{"amount":1,"unit":"cup","item":"full fat cottage cheese","group":"Base"},{"amount":2,"unit":"large","item":"eggs","group":"Base"},{"amount":0.5,"unit":"tsp","item":"garlic powder","group":"Seasoning"},{"amount":0.5,"unit":"tsp","item":"Italian seasoning","group":"Seasoning"},{"amount":0.25,"unit":"tsp","item":"salt","group":"Seasoning"},{"amount":0.25,"unit":"tsp","item":"black pepper","group":"Seasoning"},{"amount":1,"unit":"tbsp","item":"grated Parmesan cheese","group":"Topping"},{"amount":1,"unit":"tbsp","item":"olive oil","group":"Preparation"}]','[{"title":"Preheat and Prepare Pan","text":"Preheat your oven to 350 degrees Fahrenheit. Line a baking sheet with parchment paper and lightly brush it with olive oil to prevent sticking.","timer":0},{"title":"Blend the Batter","text":"Add the cottage cheese and eggs to a blender or food processor. Blend on high for about 30 seconds until the mixture is completely smooth with no visible curds.","timer":30},{"title":"Season the Mixture","text":"Pour the blended mixture into a bowl and stir in garlic powder, Italian seasoning, salt, and black pepper. Mix well until all the seasonings are evenly incorporated.","timer":0},{"title":"Bake the Flatbread","text":"Pour the batter onto the prepared parchment-lined baking sheet and spread it into an even rectangle or oval shape about a quarter inch thick. Sprinkle grated Parmesan on top and bake for 28 to 30 minutes until the edges are golden and the center is fully set.","timer":1800},{"title":"Cool and Serve","text":"Allow the flatbread to cool for at least 5 minutes before removing from the parchment. Use it as a wrap, pizza base, or slice it into pieces and serve with your favorite toppings.","timer":300}]','[{"original":"full fat cottage cheese","swap":"low fat cottage cheese for fewer calories"},{"original":"Italian seasoning","swap":"everything bagel seasoning for a different flavor profile"},{"original":"grated Parmesan cheese","swap":"nutritional yeast for a dairy free option"}]','["Skipping the blending step which leaves a lumpy texture that does not hold together","Spreading the batter too thick which results in an undercooked and soft center","Removing the flatbread from the oven too early before the edges are fully golden brown"]','["high protein","low carb","cottage cheese","flatbread","healthy","keto friendly","meal prep"]','["gluten-free","vegetarian","low-carb"]','Lunch','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Quesabirria Tacos','quesabirria-tacos','Quesabirria tacos are a stunning Mexican street food featuring slow-braised beef birria stuffed into cheese-crusted tortillas and served with a rich consomme for dipping. The combination of tender spiced meat, melted cheese, and crispy tortilla creates an unforgettable taco experience.','Slow-braised spiced beef birria packed into cheesy crispy tortillas served with rich dipping broth.','Mexican','Hard',30,210,240,6,680,45,38,36,4,'[{"amount":3,"unit":"lbs","item":"beef chuck roast cut into large chunks","group":"Protein"},{"amount":4,"unit":"count","item":"dried guajillo chiles stemmed and seeded","group":"Sauce"},{"amount":2,"unit":"count","item":"dried ancho chiles stemmed and seeded","group":"Sauce"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"Aromatics"},{"amount":1,"unit":"large","item":"white onion roughly chopped","group":"Aromatics"},{"amount":12,"unit":"count","item":"corn tortillas","group":"Base"},{"amount":2,"unit":"cups","item":"shredded Oaxaca cheese or mozzarella","group":"Cheese"},{"amount":1,"unit":"tbsp","item":"ground cumin","group":"Spices"}]','[{"title":"Prepare the Chile Sauce","text":"Toast the guajillo and ancho chiles in a dry skillet over medium heat for about 1 minute per side until fragrant. Soak them in hot water for 15 minutes until softened, then blend with garlic, half the onion, cumin, salt, and 1 cup of the soaking liquid until completely smooth.","timer":900},{"title":"Braise the Beef","text":"Season the beef chunks generously with salt and pepper. Place them in a large Dutch oven or heavy pot and pour the chile sauce over the top along with enough water to cover the meat by about an inch. Bring to a boil then reduce heat, cover, and simmer for 3 hours until the beef is fall-apart tender.","timer":10800},{"title":"Shred the Beef and Reserve Consomme","text":"Remove the beef from the pot and shred it using two forks, discarding any large pieces of fat. Skim the fat from the surface of the braising liquid and reserve this rich consomme for dipping. Stir a ladleful of the consomme into the shredded beef to keep it moist.","timer":0},{"title":"Dip and Cook the Tortillas","text":"Heat a large skillet or griddle over medium-high heat. Dip each corn tortilla briefly into the top layer of fat and consomme, then place it immediately onto the hot skillet. Add a handful of shredded Oaxaca cheese to one half of the tortilla and let it melt for about 1 minute.","timer":60},{"title":"Fill, Fold, and Serve","text":"Add a generous portion of shredded birria beef on top of the melted cheese, then fold the tortilla in half. Press gently and cook for another minute until both sides are crispy and golden. Serve immediately alongside warm bowls of consomme garnished with diced white onion and fresh cilantro for dipping.","timer":60}]','[{"original":"beef chuck roast","swap":"bone-in short ribs for a richer and deeper flavor"},{"original":"Oaxaca cheese","swap":"low-moisture mozzarella for an easy to find alternative"},{"original":"dried guajillo chiles","swap":"dried New Mexico chiles which have a similar mild heat and color"}]','["Not toasting the dried chiles before blending which results in a flat and less complex sauce","Rushing the braise by cooking on too high heat which makes the beef tough instead of tender","Skipping the consomme dip for the tortillas which is what creates the signature crispy and flavorful exterior"]','["birria","quesabirria","mexican tacos","braised beef","street food","consomme","weekend cooking"]','["gluten-free","dairy-free adaptable"]','Dinner','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Hot Honey Chicken Bowl','hot-honey-chicken-bowl','This bold and satisfying bowl features crispy golden chicken drizzled with sweet and spicy hot honey over fluffy rice and fresh toppings. It delivers the perfect balance of heat and sweetness in every single bite.','A crispy chicken rice bowl glazed with homemade hot honey and topped with fresh vegetables.','American','Medium',15,25,40,4,620,42,58,22,4,'[{"amount":1.5,"unit":"lbs","item":"boneless skinless chicken thighs","group":"Chicken"},{"amount":0.5,"unit":"cup","item":"honey","group":"Hot Honey Sauce"},{"amount":1,"unit":"tsp","item":"red pepper flakes","group":"Hot Honey Sauce"},{"amount":2,"unit":"cups","item":"long grain white rice","group":"Base"},{"amount":1,"unit":"cup","item":"shredded purple cabbage","group":"Toppings"},{"amount":2,"unit":"tbsp","item":"olive oil","group":"Chicken"},{"amount":1,"unit":"tsp","item":"garlic powder","group":"Chicken"},{"amount":2,"unit":"tbsp","item":"butter","group":"Hot Honey Sauce"}]','[{"title":"Cook the Rice","text":"Rinse 2 cups of white rice under cold water until the water runs clear. Combine with 4 cups of water and a pinch of salt in a medium saucepan, bring to a boil, then reduce heat to low, cover, and simmer for 18 minutes until fluffy.","timer":1080},{"title":"Make the Hot Honey","text":"In a small saucepan over low heat, combine honey, butter, and red pepper flakes. Stir gently for about 3 minutes until the butter melts and the mixture is smooth and fragrant. Remove from heat and set aside.","timer":180},{"title":"Season the Chicken","text":"Pat chicken thighs completely dry with paper towels. Rub evenly with olive oil, garlic powder, a generous pinch of salt, and black pepper on both sides to ensure full coverage and good browning.","timer":0},{"title":"Cook the Chicken","text":"Heat a large skillet over medium high heat. Add the seasoned chicken thighs and cook for 6 to 7 minutes per side until deeply golden and cooked through to an internal temperature of 165 degrees F. Let rest 5 minutes then slice.","timer":840},{"title":"Assemble the Bowls","text":"Scoop rice into serving bowls and layer with sliced chicken. Drizzle generously with hot honey sauce and top with shredded purple cabbage for crunch. Serve immediately while everything is warm.","timer":0}]','[{"original":"chicken thighs","swap":"boneless chicken breasts or crispy tofu"},{"original":"white rice","swap":"brown rice or cauliflower rice"},{"original":"red pepper flakes","swap":"sriracha or chipotle powder"}]','["Not drying the chicken before cooking which prevents proper browning and crispiness","Overheating the honey sauce which causes it to become bitter and too thick","Skipping the resting time after cooking the chicken which makes the slices dry out"]','["hot honey","chicken bowl","weeknight dinner","spicy sweet","rice bowl"]','["Gluten Free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Cabbage Boil','cabbage-boil','This humble and deeply comforting Southern style cabbage boil simmers tender cabbage with smoky sausage and simple seasonings in a rich flavorful broth. It is an easy one pot meal that warms you from the inside out.','A hearty Southern one pot cabbage boil with smoked sausage and bold savory seasonings.','Southern American','Easy',10,35,45,6,380,18,22,24,6,'[{"amount":1,"unit":"head","item":"green cabbage chopped into wedges","group":"Vegetables"},{"amount":1,"unit":"lb","item":"smoked sausage sliced into rounds","group":"Protein"},{"amount":4,"unit":"cups","item":"chicken broth","group":"Broth"},{"amount":3,"unit":"cloves","item":"garlic minced","group":"Aromatics"},{"amount":1,"unit":"large","item":"yellow onion roughly chopped","group":"Aromatics"},{"amount":1,"unit":"tsp","item":"smoked paprika","group":"Seasoning"},{"amount":2,"unit":"tbsp","item":"butter","group":"Seasoning"},{"amount":1,"unit":"tsp","item":"crushed red pepper","group":"Seasoning"}]','[{"title":"Brown the Sausage","text":"In a large heavy bottomed pot over medium high heat, melt butter and add sliced smoked sausage. Cook for 4 to 5 minutes stirring occasionally until the sausage rounds are nicely browned on both sides and the fat has rendered out.","timer":300},{"title":"Saute the Aromatics","text":"Add the chopped onion and minced garlic directly to the pot with the sausage drippings. Cook for 3 to 4 minutes stirring frequently until the onion softens and becomes translucent and the garlic becomes fragrant.","timer":240},{"title":"Add Seasonings and Broth","text":"Sprinkle in the smoked paprika and crushed red pepper, stir for 30 seconds to bloom the spices. Pour in the chicken broth, scraping up any browned bits from the bottom of the pot to incorporate all that flavor into the liquid.","timer":30},{"title":"Add the Cabbage","text":"Add the chopped cabbage wedges to the pot, pressing them down gently to submerge as much as possible. Bring the liquid to a boil over high heat, then reduce to a steady simmer and cover the pot with a lid.","timer":0},{"title":"Simmer Until Tender","text":"Cook covered for 20 to 25 minutes until the cabbage is completely tender and has absorbed the smoky savory broth. Taste and adjust salt and pepper as needed before ladling into deep bowls and serving hot.","timer":1500}]','[{"original":"smoked sausage","swap":"andouille sausage or smoked turkey legs"},{"original":"chicken broth","swap":"vegetable broth or water with bouillon"},{"original":"green cabbage","swap":"savoy cabbage or napa cabbage"}]','["Adding the cabbage too early before browning the sausage which removes the smoky fond from the pot","Cooking at too high a temperature which makes the cabbage fall apart and become mushy","Using too little broth which causes the cabbage to scorch on the bottom of the pot"]','["cabbage","boil","Southern","one pot","comfort food","sausage"]','["Gluten Free","Dairy Free Option"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Wisconsin Booyah','wisconsin-booyah','Wisconsin Booyah is a legendary thick and hearty stew that has been a staple at community gatherings in the Upper Midwest for well over a century. This deeply savory slow cooked stew combines chicken, beef, and vegetables into a rich and soul satisfying pot that only gets better with time.','A thick and legendary Wisconsin community stew loaded with chicken, beef, and slow cooked vegetables.','Midwestern American','Hard',30,180,210,10,480,38,34,18,7,'[{"amount":2,"unit":"lbs","item":"bone in chicken pieces","group":"Protein"},{"amount":1,"unit":"lb","item":"beef chuck cut into cubes","group":"Protein"},{"amount":4,"unit":"cups","item":"frozen mixed vegetables peas carrots green beans corn","group":"Vegetables"},{"amount":1,"unit":"head","item":"green cabbage shredded","group":"Vegetables"},{"amount":6,"unit":"cups","item":"beef broth","group":"Broth"},{"amount":3,"unit":"large","item":"russet potatoes peeled and diced","group":"Vegetables"},{"amount":1,"unit":"large","item":"yellow onion diced","group":"Aromatics"},{"amount":2,"unit":"tsp","item":"celery salt","group":"Seasoning"}]','[{"title":"Brown All the Meats","text":"In a very large heavy stockpot over medium high heat, brown the beef chuck cubes in batches for 4 to 5 minutes per batch until deeply seared on all sides. Remove and set aside, then add chicken pieces to the same pot and brown for 5 minutes per side. Do not overcrowd the pot.","timer":600},{"title":"Build the Base","text":"Return all browned meat to the pot along with the diced onion. Pour in the beef broth and add enough water to cover everything by about 2 inches. Bring to a rolling boil over high heat, then skim off any foam or impurities that rise to the surface.","timer":0},{"title":"Long Slow Simmer","text":"Reduce heat to low and add celery salt and a generous amount of black pepper. Cover the pot partially with a lid and simmer slowly for 90 minutes until the chicken is falling off the bone and the beef is completely fork tender and the broth is deeply flavored.","timer":5400},{"title":"Shred and Add Vegetables","text":"Remove the chicken pieces and carefully shred all the meat off the bones, discarding skin and bones. Return the shredded chicken to the pot along with the diced potatoes, shredded cabbage, and frozen mixed vegetables. Stir everything together well.","timer":0},{"title":"Final Cook and Season","text":"Bring the stew back up to a gentle boil over medium heat, then reduce and simmer uncovered for 30 to 40 minutes until the potatoes are fully tender and the stew has thickened to a hearty consistency. Taste carefully and adjust salt and pepper before serving in large deep bowls.","timer":2400}]','[{"original":"beef chuck","swap":"pork shoulder or additional chicken thighs"},{"original":"russet potatoes","swap":"Yukon gold potatoes or turnips"},{"original":"frozen mixed vegetables","swap":"fresh diced carrots celery and green beans"}]','["Rushing the simmer time which prevents the broth from developing its signature deep and complex flavor","Not skimming the foam off the broth early on which results in a cloudy and slightly bitter stew","Adding potatoes too early in the cooking process which causes them to completely dissolve into the broth"]','["booyah","Wisconsin","stew","community cooking","Midwestern","slow cooked","comfort food"]','["Gluten Free","Dairy Free"]','Soup and Stew','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Magic Lemon Pie','magic-lemon-pie','This classic Magic Lemon Pie creates its own creamy custard layer as it bakes, resulting in a silky smooth filling with a bright citrus flavor. The magic happens in the oven as the simple batter separates into a delicate sponge top and a luscious lemon curd bottom.','A self-layering lemon pie that magically separates into a fluffy sponge and creamy custard as it bakes.','American','Easy',15,45,60,8,310,6,42,14,1,'[{"amount":1,"unit":"cup","item":"granulated sugar","group":"filling"},{"amount":0.5,"unit":"cup","item":"unsalted butter, melted","group":"filling"},{"amount":3,"unit":"whole","item":"large eggs, separated","group":"filling"},{"amount":0.25,"unit":"cup","item":"all-purpose flour","group":"filling"},{"amount":0.25,"unit":"cup","item":"fresh lemon juice","group":"filling"},{"amount":1,"unit":"tablespoon","item":"lemon zest","group":"filling"},{"amount":1.5,"unit":"cups","item":"whole milk","group":"filling"},{"amount":1,"unit":"9-inch","item":"pre-baked pie shell","group":"crust"}]','[{"title":"Prepare the Oven and Pan","text":"Preheat your oven to 325 degrees Fahrenheit. Place the pre-baked pie shell onto a baking sheet lined with parchment paper to catch any drips and ensure even heat distribution.","timer":0},{"title":"Mix the Egg Yolk Base","text":"In a large mixing bowl, whisk together the melted butter and granulated sugar until well combined. Add the egg yolks one at a time, whisking thoroughly after each addition. Stir in the flour, fresh lemon juice, and lemon zest until a smooth batter forms.","timer":0},{"title":"Add Milk and Fold Egg Whites","text":"Gradually pour in the whole milk while whisking constantly until the mixture is completely smooth. In a separate clean bowl, beat the egg whites with a hand mixer until stiff peaks form. Gently fold the egg whites into the lemon mixture in three additions, keeping as much air as possible.","timer":0},{"title":"Bake the Pie","text":"Pour the batter carefully into the pre-baked pie shell. Place in the preheated oven and bake for 40 to 45 minutes, until the top is lightly golden and the center has just a slight jiggle. Do not open the oven during the first 30 minutes of baking.","timer":2700},{"title":"Cool and Serve","text":"Remove the pie from the oven and allow it to cool completely on a wire rack for at least one hour before slicing. The layers will set as it cools. Serve at room temperature or chilled with a dusting of powdered sugar on top.","timer":3600}]','[{"original":"whole milk","swap":"full-fat coconut milk for a dairy-free version"},{"original":"unsalted butter","swap":"coconut oil, melted, for a dairy-free alternative"},{"original":"fresh lemon juice","swap":"fresh lime juice for a tropical twist"}]','["Overmixing the egg whites into the batter which deflates them and prevents the magic layering effect","Opening the oven door too early which causes the delicate sponge layer to collapse","Not allowing the pie to cool fully before slicing which results in a runny, unset custard layer"]','["lemon","pie","custard","baking","dessert","citrus","classic","Southern"]','["vegetarian"]','Dessert','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Harissa Orange Chicken','harissa-orange-chicken','This bold and vibrant Harissa Orange Chicken combines the smoky heat of North African harissa paste with the bright sweetness of fresh orange juice for an unforgettable glaze. Tender chicken thighs are roasted until caramelized and sticky, making this dish a stunning centerpiece for any weeknight dinner.','Juicy roasted chicken thighs coated in a fiery harissa and fresh orange glaze that caramelizes beautifully in the oven.','North African','Medium',15,40,55,4,420,38,18,22,2,'[{"amount":8,"unit":"whole","item":"bone-in, skin-on chicken thighs","group":"chicken"},{"amount":3,"unit":"tablespoons","item":"harissa paste","group":"marinade"},{"amount":0.75,"unit":"cup","item":"fresh orange juice","group":"marinade"},{"amount":1,"unit":"tablespoon","item":"orange zest","group":"marinade"},{"amount":2,"unit":"tablespoons","item":"honey","group":"marinade"},{"amount":3,"unit":"cloves","item":"garlic, minced","group":"marinade"},{"amount":2,"unit":"tablespoons","item":"olive oil","group":"marinade"},{"amount":1,"unit":"teaspoon","item":"ground cumin","group":"marinade"}]','[{"title":"Make the Harissa Orange Marinade","text":"In a medium bowl, whisk together the harissa paste, fresh orange juice, orange zest, honey, minced garlic, olive oil, and ground cumin until fully combined into a smooth and glossy marinade. Taste and adjust the heat level by adding more harissa if desired.","timer":0},{"title":"Marinate the Chicken","text":"Pat the chicken thighs completely dry with paper towels and place them in a large zip-lock bag or shallow baking dish. Pour the marinade over the chicken, making sure every piece is well coated. Seal and refrigerate for at least 30 minutes, or up to 8 hours for deeper flavor.","timer":1800},{"title":"Sear the Chicken","text":"Preheat your oven to 400 degrees Fahrenheit. Heat a large oven-safe skillet over medium-high heat. Remove the chicken from the marinade, reserving the marinade. Sear the chicken skin-side down for 4 to 5 minutes until the skin is golden brown and crispy. Flip and sear for 2 more minutes.","timer":420},{"title":"Roast with the Glaze","text":"Pour the reserved marinade over the chicken in the skillet and transfer to the preheated oven. Roast for 25 to 30 minutes, basting with the pan juices halfway through, until the chicken reaches an internal temperature of 165 degrees Fahrenheit and the glaze is thick and caramelized.","timer":1800},{"title":"Rest and Serve","text":"Remove the skillet from the oven and let the chicken rest for 5 minutes before serving. Spoon the reduced glaze from the pan over each piece. Garnish with fresh orange slices and chopped cilantro. Serve over couscous or with flatbread to soak up the flavorful sauce.","timer":300}]','[{"original":"harissa paste","swap":"sriracha mixed with a pinch of smoked paprika for a similar smoky heat"},{"original":"bone-in chicken thighs","swap":"boneless skinless chicken thighs for a quicker cooking option"},{"original":"honey","swap":"maple syrup for a slightly deeper sweetness"}]','["Not patting the chicken dry before searing which causes steaming instead of proper browning and crispy skin","Skipping the searing step and going straight to the oven which results in pale, soft skin","Not basting the chicken during roasting which leads to a less caramelized and flavorful glaze"]','["chicken","harissa","orange","spicy","roasted","North African","weeknight","glaze"]','["gluten-free","dairy-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Garlic Butter Steak Bites','garlic-butter-steak-bites','These irresistible Garlic Butter Steak Bites are seared in a screaming hot skillet until perfectly caramelized on the outside and juicy and tender on the inside. Tossed in a rich garlic herb butter sauce, they come together in under 15 minutes and are guaranteed to impress at any gathering.','Tender bite-sized pieces of sirloin steak seared to perfection and tossed in a rich garlic herb butter sauce.','American','Easy',10,10,20,4,480,42,3,33,0,'[{"amount":1.5,"unit":"pounds","item":"sirloin steak, cut into 1-inch cubes","group":"steak"},{"amount":4,"unit":"tablespoons","item":"unsalted butter","group":"sauce"},{"amount":5,"unit":"cloves","item":"garlic, minced","group":"sauce"},{"amount":1,"unit":"tablespoon","item":"fresh rosemary, finely chopped","group":"sauce"},{"amount":1,"unit":"tablespoon","item":"fresh thyme leaves","group":"sauce"},{"amount":1,"unit":"tablespoon","item":"olive oil","group":"cooking"},{"amount":1,"unit":"teaspoon","item":"kosher salt","group":"seasoning"},{"amount":0.5,"unit":"teaspoon","item":"black pepper, freshly cracked","group":"seasoning"}]','[{"title":"Prep and Season the Steak","text":"Remove the steak cubes from the refrigerator 20 minutes before cooking to bring them to room temperature. Pat each piece completely dry with paper towels to ensure a proper sear. Season generously with kosher salt and freshly cracked black pepper on all sides, pressing the seasoning gently into the meat.","timer":1200},{"title":"Heat the Skillet","text":"Place a large cast iron skillet or heavy-bottomed pan over high heat and allow it to heat for at least 2 to 3 minutes until it is smoking hot. Add the olive oil and swirl to coat the pan. The oil should shimmer and just begin to smoke before you add the steak.","timer":180},{"title":"Sear the Steak Bites","text":"Add the steak cubes in a single layer, making sure do not overcrowd the pan. Work in batches if necessary. Sear without moving for 1 to 2 minutes per side until a deep brown crust forms on each piece. The steak bites should reach medium-rare to medium doneness internally.","timer":120},{"title":"Make the Garlic Butter Sauce","text":"Reduce the heat to medium-low and push the steak bites to the side of the pan. Add the butter to the empty side of the pan and let it melt. Once melted and foamy, add the minced garlic, rosemary, and thyme. Cook the garlic for 30 to 45 seconds until fragrant, do not let it burn.","timer":45},{"title":"Toss and Serve","text":"Toss all of the steak bites in the garlic herb butter until every piece is evenly coated and glistening. Remove from heat immediately and transfer to a serving platter. Spoon any remaining butter sauce from the pan over the top. Serve immediately with toothpicks as an appetizer or over mashed potatoes as a main.","timer":0}]','[{"original":"sirloin steak","swap":"ribeye or tenderloin for a richer and more buttery flavor"},{"original":"fresh rosemary","swap":"dried rosemary using half the amount in a pinch"},{"original":"unsalted butter","swap":"ghee for a higher smoke point and nutty flavor"}]','["Overcrowding the pan with too many steak pieces which causes them to steam rather than sear and develop a crust","Not drying the steak cubes before cooking which produces excess moisture and prevents browning","Moving the steak pieces too soon before a proper crust has formed, resulting in the meat tearing and losing its juices"]','["steak","garlic butter","beef","quick","appetizer","keto","low-carb","cast iron"]','["gluten-free","keto","low-carb"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Creamy Cajun Pasta Skillet','creamy-cajun-pasta-skillet','This bold and smoky one-pan pasta dish brings together tender chicken, colorful bell peppers, and a rich cream sauce loaded with Cajun spices. It is ready in under 30 minutes and delivers restaurant-quality flavor with minimal cleanup.','A spicy and creamy one-skillet pasta packed with Cajun seasoning, chicken, and vegetables.','Cajun','Easy',10,20,30,4,620,38,58,26,4,'[{"amount":2,"unit":"tbsp","item":"Cajun seasoning","group":"Spices"},{"amount":1,"unit":"lb","item":"boneless skinless chicken breast, sliced","group":"Protein"},{"amount":12,"unit":"oz","item":"penne pasta","group":"Pasta"},{"amount":1,"unit":"cup","item":"heavy cream","group":"Sauce"},{"amount":1,"unit":"cup","item":"chicken broth","group":"Sauce"},{"amount":1,"unit":"whole","item":"red bell pepper, sliced","group":"Vegetables"},{"amount":3,"unit":"cloves","item":"garlic, minced","group":"Aromatics"},{"amount":1,"unit":"cup","item":"shredded Parmesan cheese","group":"Dairy"}]','[{"title":"Season and Sear the Chicken","text":"Toss the sliced chicken breast with Cajun seasoning until fully coated. Heat a large skillet over medium-high heat with a drizzle of oil and sear the chicken for 4 to 5 minutes per side until golden and cooked through. Remove and set aside.","timer":600},{"title":"Saute the Vegetables","text":"In the same skillet, add the sliced red bell pepper and minced garlic. Saute over medium heat for 3 to 4 minutes until the pepper softens and the garlic becomes fragrant.","timer":240},{"title":"Build the Cream Sauce","text":"Pour in the chicken broth and heavy cream, stirring to combine with the vegetables. Bring the mixture to a gentle simmer and cook for 2 minutes to allow the flavors to meld.","timer":120},{"title":"Cook the Pasta in the Sauce","text":"Add the dry penne pasta directly into the skillet, ensuring it is submerged in the liquid. Cover and cook over medium heat for 12 to 14 minutes, stirring occasionally, until the pasta is al dente and the sauce has thickened.","timer":840},{"title":"Finish and Serve","text":"Return the seared chicken to the skillet and stir in the shredded Parmesan cheese. Toss everything together until the cheese melts and coats the pasta evenly. Serve immediately garnished with extra Cajun seasoning if desired.","timer":120}]','[{"original":"heavy cream","swap":"half-and-half for a lighter sauce"},{"original":"chicken breast","swap":"shrimp for a seafood version"},{"original":"penne pasta","swap":"rigatoni or rotini for a different texture"}]','["Adding too much Cajun seasoning without tasting first, which can make the dish overwhelmingly salty","Not stirring the pasta while it cooks in the sauce, causing it to stick to the bottom of the skillet","Cooking on too high heat which causes the cream sauce to break and become greasy"]','["cajun","pasta","one-pan","spicy","weeknight","creamy","chicken","quick"]','["gluten-free adaptable"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('French Onion Chicken','french-onion-chicken','This comforting skillet dish transforms classic French onion soup into a hearty chicken dinner with deeply caramelized onions, savory broth, and a blanket of melted Gruyere cheese. Each bite delivers rich, sweet onion flavor paired with juicy pan-seared chicken that the whole family will love.','Juicy seared chicken smothered in caramelized onions and melted Gruyere cheese inspired by classic French onion soup.','French','Medium',10,45,55,4,540,44,18,30,2,'[{"amount":4,"unit":"whole","item":"boneless skinless chicken thighs","group":"Protein"},{"amount":3,"unit":"large","item":"yellow onions, thinly sliced","group":"Vegetables"},{"amount":2,"unit":"tbsp","item":"unsalted butter","group":"Fat"},{"amount":1,"unit":"cup","item":"beef broth","group":"Sauce"},{"amount":1,"unit":"tbsp","item":"Worcestershire sauce","group":"Sauce"},{"amount":1,"unit":"tsp","item":"fresh thyme leaves","group":"Herbs"},{"amount":1.5,"unit":"cups","item":"shredded Gruyere cheese","group":"Dairy"},{"amount":2,"unit":"cloves","item":"garlic, minced","group":"Aromatics"}]','[{"title":"Sear the Chicken","text":"Season the chicken thighs generously with salt and pepper on both sides. Heat a large oven-safe skillet over medium-high heat and sear the chicken for 4 to 5 minutes per side until a deep golden crust forms. Remove the chicken and set aside on a plate.","timer":600},{"title":"Caramelize the Onions","text":"Reduce the heat to medium-low and melt the butter in the same skillet. Add the sliced onions and cook, stirring every 5 minutes, for 30 to 35 minutes until the onions are deeply golden, sweet, and caramelized. Add the minced garlic in the last 2 minutes of cooking.","timer":2100},{"title":"Deglaze and Build the Sauce","text":"Pour the beef broth and Worcestershire sauce into the skillet, scraping up any browned bits from the bottom. Stir in the fresh thyme and let the mixture simmer for 3 to 4 minutes until slightly reduced and fragrant.","timer":240},{"title":"Return Chicken and Simmer","text":"Nestle the seared chicken thighs back into the skillet on top of the caramelized onions. Spoon some of the onion mixture over each piece of chicken and cook over medium heat for 8 to 10 minutes until the chicken reaches an internal temperature of 165 degrees F.","timer":600},{"title":"Top with Cheese and Broil","text":"Preheat the broiler to high. Sprinkle the shredded Gruyere cheese evenly over the chicken and onions. Place the skillet under the broiler for 2 to 3 minutes until the cheese is bubbly, melted, and lightly browned. Serve immediately directly from the skillet.","timer":180}]','[{"original":"Gruyere cheese","swap":"Swiss cheese or provolone for a milder flavor"},{"original":"beef broth","swap":"chicken broth for a lighter sauce"},{"original":"chicken thighs","swap":"boneless chicken breasts, adjusting cook time accordingly"}]','["Rushing the caramelization of onions by cooking on high heat, which burns them instead of developing their natural sweetness","Skipping the deglazing step which removes essential flavor from the fond stuck to the pan","Using pre-shredded packaged cheese which does not melt as smoothly as freshly shredded Gruyere"]','["french","comfort food","chicken","caramelized onions","cheesy","skillet","weeknight","cozy"]','["gluten-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Skillet Lasagna Roll-Ups','skillet-lasagna-roll-ups','These fun and satisfying lasagna roll-ups are filled with creamy ricotta and savory ground beef, then simmered directly in a rich marinara sauce right in the skillet. The result is all the cozy flavors of classic lasagna without the long bake time or multiple pans to wash.','Cheesy ricotta and beef filled lasagna noodles simmered in marinara sauce all in one skillet.','Italian','Medium',20,30,50,4,670,42,62,28,5,'[{"amount":8,"unit":"whole","item":"lasagna noodles, cooked al dente","group":"Pasta"},{"amount":1,"unit":"lb","item":"ground beef","group":"Protein"},{"amount":1.5,"unit":"cups","item":"ricotta cheese","group":"Dairy"},{"amount":2,"unit":"cups","item":"marinara sauce","group":"Sauce"},{"amount":1,"unit":"cup","item":"shredded mozzarella cheese","group":"Dairy"},{"amount":1,"unit":"tsp","item":"Italian seasoning","group":"Spices"},{"amount":2,"unit":"cloves","item":"garlic, minced","group":"Aromatics"},{"amount":0.25,"unit":"cup","item":"fresh basil leaves, chopped","group":"Herbs"}]','[{"title":"Prepare the Filling","text":"Brown the ground beef in a large skillet over medium-high heat, breaking it up as it cooks, for about 6 to 7 minutes until no pink remains. Drain excess fat, then stir in the minced garlic, Italian seasoning, salt, and pepper. Remove from heat and let the beef cool slightly before mixing in the ricotta cheese until fully combined.","timer":420},{"title":"Fill and Roll the Noodles","text":"Lay each cooked lasagna noodle flat on a clean work surface. Spread a generous 3 to 4 tablespoons of the beef and ricotta filling evenly across the entire length of each noodle. Carefully roll each noodle up tightly from one end to form compact rolls.","timer":300},{"title":"Build the Skillet","text":"Pour the marinara sauce into the same large skillet and spread it into an even layer over medium heat. Gently place each lasagna roll-up seam side down into the marinara sauce, arranging them snugly so they hold their shape during cooking.","timer":120},{"title":"Simmer Until Cooked Through","text":"Cover the skillet with a lid and cook over medium-low heat for 15 to 18 minutes until the roll-ups are heated through and the sauce is bubbling around the edges. Check halfway through and spoon sauce over the tops of the rolls to keep them moist.","timer":1080},{"title":"Add Cheese and Serve","text":"Uncover the skillet and sprinkle the shredded mozzarella cheese generously over the top of the roll-ups. Cover for an additional 2 minutes until the cheese is fully melted and gooey. Garnish with fresh chopped basil and serve directly from the skillet.","timer":120}]','[{"original":"ground beef","swap":"Italian sausage for a more robust and spiced filling"},{"original":"ricotta cheese","swap":"cottage cheese blended smooth for a lighter option"},{"original":"marinara sauce","swap":"homemade tomato basil sauce for a fresher flavor"}]','["Overfilling the lasagna noodles which causes them to unroll and fall apart in the sauce","Not cooking the noodles to al dente before rolling, resulting in mushy texture after simmering","Cooking on too high heat which scorches the bottom of the sauce before the roll-ups are heated through"]','["italian","lasagna","pasta","comfort food","skillet","cheesy","weeknight","ground beef"]','["nut-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Honey Garlic Chicken Thighs','honey-garlic-chicken-thighs','Tender and juicy chicken thighs glazed in a rich honey garlic sauce that caramelizes beautifully in the pan. This simple yet impressive dish delivers bold flavors with minimal effort and comes together in under 40 minutes.','Sticky sweet and savory chicken thighs cooked in a luscious honey garlic glaze.','American','Easy',10,25,35,4,420,32,18,24,1,'[{"amount":8,"unit":"pieces","item":"bone-in skin-on chicken thighs","group":"Chicken"},{"amount":6,"unit":"cloves","item":"garlic minced","group":"Sauce"},{"amount":4,"unit":"tablespoons","item":"honey","group":"Sauce"},{"amount":3,"unit":"tablespoons","item":"soy sauce","group":"Sauce"},{"amount":2,"unit":"tablespoons","item":"olive oil","group":"Cooking"},{"amount":1,"unit":"tablespoon","item":"apple cider vinegar","group":"Sauce"},{"amount":1,"unit":"teaspoon","item":"smoked paprika","group":"Seasoning"},{"amount":1,"unit":"teaspoon","item":"black pepper","group":"Seasoning"}]','[{"title":"Season the Chicken","text":"Pat the chicken thighs completely dry with paper towels. Season both sides generously with smoked paprika and black pepper. Drying the chicken is essential for achieving a crispy golden skin when it hits the pan.","timer":0},{"title":"Sear the Chicken","text":"Heat olive oil in a large oven-safe skillet over medium-high heat. Place chicken thighs skin side down and sear without moving them for 7 to 8 minutes until the skin is deep golden and crispy. Flip and cook for another 4 minutes on the other side.","timer":480},{"title":"Make the Honey Garlic Sauce","text":"Remove the chicken temporarily and reduce heat to medium. Add minced garlic to the pan drippings and cook for 1 minute until fragrant. Pour in honey, soy sauce, and apple cider vinegar, stirring to combine and scraping up any browned bits from the bottom of the pan.","timer":60},{"title":"Finish Cooking in Sauce","text":"Return the chicken thighs to the pan skin side up and spoon the sauce over them. Cook over medium heat for 10 to 12 minutes, basting the chicken every few minutes, until the internal temperature reaches 165 degrees Fahrenheit and the sauce has thickened into a sticky glaze.","timer":720},{"title":"Rest and Serve","text":"Remove the pan from heat and let the chicken rest for 5 minutes before serving. Spoon additional glaze from the pan over each piece and garnish with fresh parsley if desired. Serve alongside steamed rice or roasted vegetables.","timer":300}]','[{"original":"soy sauce","swap":"coconut aminos for a gluten free option"},{"original":"apple cider vinegar","swap":"fresh lemon juice for a brighter citrus note"},{"original":"bone-in chicken thighs","swap":"boneless skinless thighs for faster cooking time"}]','["Not patting the chicken dry before searing which leads to steaming instead of browning","Moving the chicken too early during the sear before a crust has properly formed","Cooking on heat that is too high which burns the honey in the glaze"]','["chicken","honey","garlic","weeknight dinner","skillet","sticky","glazed"]','["Gluten-Free Optional","Dairy-Free"]','Dinner','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Mexican Street Corn Chicken','mexican-street-corn-chicken','This vibrant dish combines juicy seasoned chicken with the bold and creamy flavors of elote, the beloved Mexican street corn. Topped with cotija cheese, chili powder, and a zesty lime crema, every bite is an explosion of smoky and tangy goodness.','Grilled chicken topped with creamy elote-style street corn topping for a bold and festive meal.','Mexican','Medium',15,25,40,4,490,38,22,27,3,'[{"amount":4,"unit":"pieces","item":"boneless skinless chicken breasts","group":"Chicken"},{"amount":2,"unit":"cups","item":"corn kernels fresh or frozen","group":"Corn Topping"},{"amount":0.5,"unit":"cup","item":"mayonnaise","group":"Crema"},{"amount":0.5,"unit":"cup","item":"cotija cheese crumbled","group":"Topping"},{"amount":2,"unit":"tablespoons","item":"fresh lime juice","group":"Crema"},{"amount":2,"unit":"teaspoons","item":"chili powder","group":"Seasoning"},{"amount":1,"unit":"teaspoon","item":"garlic powder","group":"Seasoning"},{"amount":2,"unit":"tablespoons","item":"fresh cilantro chopped","group":"Garnish"}]','[{"title":"Season and Prep the Chicken","text":"Pound the chicken breasts to an even thickness of about three quarters of an inch for uniform cooking. Season both sides with chili powder, garlic powder, salt, and pepper. Let the chicken rest at room temperature for 10 minutes while you prepare the corn topping.","timer":600},{"title":"Char the Corn","text":"Heat a dry cast iron skillet or grill pan over high heat. Add the corn kernels in a single layer and cook without stirring for 3 to 4 minutes until nicely charred. Stir and continue cooking for another 2 minutes. Remove the corn and set aside to cool slightly.","timer":360},{"title":"Cook the Chicken","text":"In the same skillet add a drizzle of oil over medium-high heat. Cook the seasoned chicken breasts for 6 to 7 minutes per side until golden brown on the outside and the internal temperature reads 165 degrees Fahrenheit. Remove from heat and let rest for 5 minutes.","timer":840},{"title":"Make the Street Corn Topping","text":"In a bowl combine the charred corn, mayonnaise, half the cotija cheese, lime juice, and a pinch of chili powder. Stir well until everything is evenly coated. Taste and adjust seasoning with salt and additional lime juice as needed.","timer":0},{"title":"Assemble and Serve","text":"Spoon the street corn mixture generously over each rested chicken breast. Top with the remaining cotija cheese and fresh cilantro. Serve immediately with lime wedges on the side for extra brightness and a side of Mexican rice or warm tortillas.","timer":0}]','[{"original":"cotija cheese","swap":"feta cheese for a similar salty and crumbly texture"},{"original":"mayonnaise","swap":"sour cream or Greek yogurt for a lighter crema"},{"original":"fresh corn kernels","swap":"canned corn drained and patted dry when fresh is not available"}]','["Using wet corn kernels which causes steaming instead of charring in the pan","Skipping the step of pounding chicken to even thickness causing uneven cooking","Adding the corn topping while the chicken is still very hot which melts the crema and makes it runny"]','["chicken","Mexican","street corn","elote","cotija","lime","summer","grilled"]','["Gluten-Free"]','Dinner','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Cheesy Taco Pasta','cheesy-taco-pasta','This one-pot wonder mashup combines all the bold and spicy flavors of a classic taco with comforting and creamy pasta in one irresistible dish. Ground beef seasoned with homemade taco spices gets tossed with tender pasta and melted cheese for a family-friendly dinner that is ready in 30 minutes.','A creamy and cheesy one-pot pasta loaded with seasoned taco beef and melted cheddar.','Tex-Mex','Easy',10,20,30,6,580,34,52,26,4,'[{"amount":1,"unit":"pound","item":"ground beef 80 percent lean","group":"Protein"},{"amount":12,"unit":"ounces","item":"rotini or penne pasta","group":"Pasta"},{"amount":2,"unit":"tablespoons","item":"taco seasoning","group":"Seasoning"},{"amount":1,"unit":"can","item":"diced tomatoes with green chiles 14 ounces","group":"Sauce"},{"amount":2,"unit":"cups","item":"beef broth","group":"Liquid"},{"amount":2,"unit":"cups","item":"shredded cheddar cheese","group":"Cheese"},{"amount":1,"unit":"medium","item":"yellow onion diced","group":"Aromatics"},{"amount":3,"unit":"cloves","item":"garlic minced","group":"Aromatics"}]','[{"title":"Brown the Ground Beef","text":"Heat a large deep skillet or Dutch oven over medium-high heat. Add the ground beef and diced onion, breaking the meat apart with a wooden spoon. Cook for 6 to 8 minutes until the beef is browned and the onion is softened. Drain any excess fat from the pan.","timer":480},{"title":"Add Aromatics and Seasoning","text":"Reduce heat to medium and add the minced garlic to the beef mixture. Cook for 1 minute until fragrant. Sprinkle the taco seasoning over the meat and stir well to coat everything evenly in the spices.","timer":60},{"title":"Cook the Pasta in the Pan","text":"Pour in the diced tomatoes with green chiles and the beef broth, stirring to combine. Add the dry pasta directly to the pan and press it down so it is mostly submerged in the liquid. Bring to a boil, then reduce to a simmer, cover, and cook for 12 to 14 minutes stirring occasionally until the pasta is al dente and most of the liquid is absorbed.","timer":840},{"title":"Add the Cheese","text":"Remove the lid and reduce heat to low. Sprinkle the shredded cheddar cheese evenly over the top of the pasta. Stir gently to incorporate the cheese throughout the dish until it is fully melted and the sauce is thick and creamy. If the mixture seems too thick add a splash of broth to loosen it.","timer":120},{"title":"Serve with Toppings","text":"Serve the cheesy taco pasta immediately while it is hot and melty. Top individual bowls with sour cream, sliced jalapenos, fresh cilantro, or crushed tortilla chips for added crunch. Leftovers reheat well with a small splash of water or broth to revive the creamy sauce.","timer":0}]','[{"original":"ground beef","swap":"ground turkey or ground chicken for a lighter version"},{"original":"cheddar cheese","swap":"Monterey Jack or a Mexican blend cheese for extra meltability"},{"original":"taco seasoning packet","swap":"a mix of cumin, chili powder, garlic powder, and oregano made from scratch"}]','["Not draining the fat after browning the beef which makes the final dish greasy","Lifting the lid too frequently while the pasta cooks causing too much steam to escape and uneven cooking","Adding all the cheese at once over high heat which can cause it to clump rather than melt smoothly"]','["pasta","taco","beef","cheesy","one pot","weeknight","kid friendly","Tex-Mex"]','["Nut-Free"]','Dinner','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Lemon Garlic Salmon Asparagus','lemon-garlic-salmon-asparagus','This vibrant one-pan meal combines tender salmon fillets with crisp asparagus in a bright lemon garlic butter sauce. It comes together in under 30 minutes making it perfect for busy weeknights without sacrificing flavor or nutrition.','A fast and flavorful one-pan salmon and asparagus dish with zesty lemon garlic butter.','American','Easy',10,18,28,4,420,38,8,26,3,'[{"amount":4,"unit":"fillets","item":"salmon fillets skin on","group":"Main"},{"amount":1,"unit":"lb","item":"fresh asparagus trimmed","group":"Vegetables"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"Aromatics"},{"amount":2,"unit":"tbsp","item":"unsalted butter","group":"Sauce"},{"amount":2,"unit":"whole","item":"lemons juiced and zested","group":"Sauce"},{"amount":2,"unit":"tbsp","item":"olive oil","group":"Cooking"},{"amount":1,"unit":"tsp","item":"smoked paprika","group":"Seasoning"},{"amount":0.5,"unit":"tsp","item":"red pepper flakes","group":"Seasoning"}]','[{"title":"Preheat and Prepare","text":"Preheat your oven to 400 degrees F. Pat the salmon fillets dry with paper towels and season generously with salt pepper and smoked paprika on both sides. Arrange the trimmed asparagus on a large rimmed baking sheet and drizzle with one tablespoon of olive oil tossing to coat evenly.","timer":0},{"title":"Season the Salmon","text":"Place the seasoned salmon fillets on the baking sheet alongside the asparagus. Drizzle the remaining olive oil over the salmon and scatter the minced garlic over both the salmon and asparagus. Sprinkle red pepper flakes over everything for a gentle heat.","timer":0},{"title":"Make the Lemon Butter","text":"In a small saucepan over low heat melt the butter and stir in the lemon juice and lemon zest. Drizzle this mixture evenly over the salmon fillets and asparagus ensuring everything is well coated with the bright citrus butter sauce.","timer":120},{"title":"Roast to Perfection","text":"Transfer the baking sheet to the preheated oven and roast for 14 to 18 minutes depending on the thickness of your salmon. The salmon should flake easily with a fork and register 145 degrees F internally while the asparagus should be tender with slightly caramelized tips.","timer":1080},{"title":"Serve Immediately","text":"Remove the baking sheet from the oven and let the salmon rest for two minutes. Plate the salmon fillets alongside generous portions of asparagus and spoon any pan juices over the top. Garnish with extra lemon slices and fresh parsley if desired before serving.","timer":120}]','[{"original":"salmon fillets","swap":"trout or halibut fillets of similar thickness"},{"original":"fresh asparagus","swap":"broccolini or green beans for a similar tender crisp result"},{"original":"unsalted butter","swap":"ghee or a dairy free butter alternative for the same richness"}]','["Skipping the step of patting the salmon dry which leads to steaming instead of roasting and results in pale soggy skin","Overcooking the salmon past 145 degrees F which causes it to become dry and chalky rather than moist and flaky","Not trimming the woody ends from the asparagus causing tough chewy bites in the finished dish"]','["salmon","asparagus","lemon","garlic","one-pan","weeknight","seafood","roasted","healthy","gluten-free"]','["Gluten-Free","Low-Carb","Pescatarian"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Crispy Gnocchi Pesto','crispy-gnocchi-pesto','Pan-fried gnocchi achieves an irresistible golden crust on the outside while remaining pillowy soft on the inside and then gets tossed in vibrant homemade basil pesto. This dish transforms a humble pantry staple into an impressive restaurant quality meal in just 25 minutes.','Golden pan-fried gnocchi tossed in fresh basil pesto for a quick and satisfying Italian-inspired meal.','Italian','Easy',5,20,25,4,510,14,62,24,4,'[{"amount":2,"unit":"lbs","item":"shelf stable or fresh gnocchi","group":"Main"},{"amount":3,"unit":"tbsp","item":"olive oil divided","group":"Cooking"},{"amount":0.5,"unit":"cup","item":"fresh basil pesto store bought or homemade","group":"Sauce"},{"amount":0.5,"unit":"cup","item":"cherry tomatoes halved","group":"Vegetables"},{"amount":0.25,"unit":"cup","item":"freshly grated Parmesan cheese","group":"Topping"},{"amount":3,"unit":"cloves","item":"garlic minced","group":"Aromatics"},{"amount":0.25,"unit":"tsp","item":"black pepper freshly ground","group":"Seasoning"},{"amount":2,"unit":"tbsp","item":"pine nuts toasted","group":"Topping"}]','[{"title":"Dry the Gnocchi","text":"If using fresh gnocchi spread them on a clean kitchen towel and pat gently to remove excess moisture. This step is critical for achieving a proper golden crust rather than steaming the gnocchi in the pan. Shelf stable gnocchi can go straight from the package without any pre-cooking or boiling.","timer":0},{"title":"Sear Until Golden","text":"Heat two tablespoons of olive oil in a large nonstick or cast iron skillet over medium high heat until shimmering. Add the gnocchi in a single layer without crowding the pan and cook undisturbed for 3 to 4 minutes until a deep golden crust forms on the bottom. Flip and cook for another 2 to 3 minutes on the other side.","timer":420},{"title":"Add Garlic and Tomatoes","text":"Push the crisped gnocchi to the sides of the pan and add the remaining tablespoon of olive oil to the center. Add the minced garlic and cook for 30 seconds until fragrant then add the halved cherry tomatoes. Cook stirring occasionally for 3 minutes until the tomatoes begin to blister and release their juices.","timer":210},{"title":"Toss with Pesto","text":"Remove the pan from the heat and add the basil pesto to the gnocchi and tomato mixture. Toss everything together gently ensuring each piece of gnocchi is well coated in the vibrant green sauce. The residual heat will warm the pesto without cooking out its fresh flavor.","timer":60},{"title":"Finish and Serve","text":"Transfer the pesto gnocchi to serving bowls and top generously with freshly grated Parmesan cheese and the toasted pine nuts. Season with freshly ground black pepper and add a drizzle of good quality olive oil if desired. Serve immediately while the gnocchi retain their crispy exterior.","timer":0}]','[{"original":"fresh basil pesto","swap":"sun-dried tomato pesto or arugula walnut pesto for a different flavor profile"},{"original":"pine nuts","swap":"toasted walnuts or slivered almonds which provide a similar crunch at a lower cost"},{"original":"Parmesan cheese","swap":"Pecorino Romano for a sharper saltier finish or nutritional yeast for a dairy free option"}]','["Boiling the gnocchi before pan-frying which makes them waterlogged and prevents the development of a golden crust","Overcrowding the skillet with too many gnocchi at once causing them to steam rather than sear and leaving them soft and gummy","Adding the pesto while the pan is still over high heat which causes the basil to turn dark and bitter losing its fresh vibrant flavor"]','["gnocchi","pesto","Italian","vegetarian","quick","pan-fried","crispy","basil","comfort food","weeknight"]','["Vegetarian"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Greek Lemon Chicken Soup','greek-lemon-chicken-soup','This classic Avgolemono soup features tender shredded chicken and orzo simmered in a rich homemade broth that gets thickened and brightened by a silky egg and lemon mixture. The result is a velvety comforting soup that is simultaneously hearty and refreshing with a beautiful pale golden color.','A creamy and comforting Greek egg-lemon soup with tender chicken and orzo that is ready in 45 minutes.','Greek','Medium',10,35,45,6,310,28,24,11,2,'[{"amount":1.5,"unit":"lbs","item":"boneless skinless chicken breasts","group":"Main"},{"amount":8,"unit":"cups","item":"low sodium chicken broth","group":"Base"},{"amount":0.75,"unit":"cup","item":"orzo pasta uncooked","group":"Starch"},{"amount":3,"unit":"whole","item":"large eggs","group":"Thickener"},{"amount":3,"unit":"whole","item":"lemons juiced about half cup","group":"Acid"},{"amount":1,"unit":"medium","item":"yellow onion finely diced","group":"Aromatics"},{"amount":2,"unit":"stalks","item":"celery finely diced","group":"Aromatics"},{"amount":1,"unit":"tsp","item":"dried dill or 2 tbsp fresh dill","group":"Seasoning"}]','[{"title":"Simmer the Chicken","text":"Pour the chicken broth into a large pot and bring to a gentle boil over medium high heat. Add the whole chicken breasts along with the diced onion and celery and reduce heat to medium. Simmer uncovered for 18 to 20 minutes until the chicken is fully cooked through and registers 165 degrees F internally.","timer":1200},{"title":"Shred and Cook Orzo","text":"Remove the cooked chicken from the pot using tongs and set aside on a cutting board to rest and cool slightly. Add the orzo to the still simmering broth and cook for 8 to 9 minutes until just tender. While the orzo cooks use two forks to shred the chicken into bite sized pieces and then return it to the pot.","timer":540},{"title":"Prepare the Avgolemono","text":"In a medium bowl whisk together the eggs until light and frothy which takes about one minute of vigorous whisking. Slowly whisk in the fresh lemon juice and continue whisking until the mixture is smooth and well combined. This egg lemon mixture is the defining element of Avgolemono and must be done carefully.","timer":60},{"title":"Temper the Eggs","text":"This step is essential to prevent the eggs from scrambling. Ladle about two cups of the hot broth from the pot very slowly into the egg lemon mixture while whisking constantly and vigorously. This gradually raises the temperature of the eggs. Then slowly pour the tempered mixture back into the pot while stirring continuously.","timer":120},{"title":"Final Simmer and Season","text":"Reduce the heat to low and gently stir the soup for 2 to 3 minutes allowing it to thicken slightly to a creamy velvety consistency. Do not let the soup boil after adding the egg mixture. Season generously with salt and pepper then stir in the dill. Ladle into bowls and garnish with extra lemon slices and fresh dill.","timer":180}]','[{"original":"orzo pasta","swap":"long grain white rice or small ditalini pasta for a similar starchy texture"},{"original":"boneless skinless chicken breasts","swap":"rotisserie chicken shredded which cuts the cooking time significantly"},{"original":"fresh lemons","swap":"bottled lemon juice in a pinch though fresh lemons provide a much brighter cleaner flavor"}]','["Adding the egg lemon mixture directly to the boiling soup without tempering which causes the eggs to curdle and creates an unpleasant scrambled texture","Allowing the soup to boil vigorously after the Avgolemono has been added which breaks the emulsion and ruins the creamy consistency","Under-whisking the eggs before adding the lemon juice resulting in a thin sauce that does not properly thicken and enrich the broth"]','["Greek","soup","lemon","chicken","avgolemono","orzo","comfort food","egg-lemon","Mediterranean","winter"]','["Gluten-Free Option","Dairy-Free"]','Soup','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Italian Pastina Soup','italian-pastina-soup','This classic Italian comfort soup features tiny star-shaped pasta cooked in a rich chicken broth with vegetables and fresh herbs. It is a simple yet deeply nourishing dish that has been passed down through Italian families for generations.','A cozy Italian soup with tiny pastina pasta simmered in golden chicken broth with carrots and celery.','Italian','Easy',10,20,30,4,210,12,28,6,2,'[{"amount":6,"unit":"cups","item":"chicken broth","group":"Base"},{"amount":1,"unit":"cup","item":"pastina or stelline pasta","group":"Pasta"},{"amount":2,"unit":"medium","item":"carrots diced","group":"Vegetables"},{"amount":2,"unit":"stalks","item":"celery diced","group":"Vegetables"},{"amount":1,"unit":"small","item":"yellow onion finely chopped","group":"Vegetables"},{"amount":2,"unit":"cloves","item":"garlic minced","group":"Aromatics"},{"amount":2,"unit":"tablespoons","item":"olive oil","group":"Fat"},{"amount":0.5,"unit":"cup","item":"freshly grated Parmesan cheese","group":"Topping"}]','[{"title":"Saute the Vegetables","text":"Heat olive oil in a large pot over medium heat. Add the chopped onion carrots and celery and cook for 5 to 6 minutes until softened. Add the minced garlic and cook for 1 more minute until fragrant.","timer":360},{"title":"Add the Broth","text":"Pour in the chicken broth and bring the mixture to a gentle boil over medium high heat. Season with salt and black pepper to taste. Allow the broth to develop flavor for about 5 minutes.","timer":300},{"title":"Cook the Pastina","text":"Add the pastina pasta directly to the simmering broth. Stir frequently to prevent the pasta from sticking together. Cook for 5 to 7 minutes until the pasta is tender and has absorbed some of the broth.","timer":420},{"title":"Adjust Consistency","text":"If the soup is too thick add an additional half cup of warm chicken broth to reach your desired consistency. Taste and adjust seasoning with salt and pepper as needed. Keep the heat on low while adjusting.","timer":120},{"title":"Serve and Garnish","text":"Ladle the hot pastina soup into bowls and top generously with freshly grated Parmesan cheese. Serve immediately with crusty Italian bread on the side for dipping. Enjoy this warm and comforting bowl of goodness.","timer":0}]','[{"original":"pastina pasta","swap":"orzo or acini di pepe pasta"},{"original":"chicken broth","swap":"vegetable broth for a vegetarian version"},{"original":"Parmesan cheese","swap":"Pecorino Romano cheese"}]','["Overcooking the pastina which causes it to become mushy and absorb too much broth","Not stirring the pasta frequently enough causing it to clump together at the bottom","Adding too much pasta at once which makes the soup thick and stew-like rather than brothy"]','["soup","italian","comfort food","pasta","quick","weeknight dinner","winter"]','["Gluten-Free adaptable","Nut-Free"]','Soup','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Million Dollar Soup','million-dollar-soup','Million Dollar Soup is a luxuriously creamy and hearty dish loaded with white beans ground sausage cream cheese and spinach in a savory broth. Every spoonful delivers rich indulgent flavors that taste like it took hours to make but comes together in under 40 minutes.','A rich and creamy sausage and white bean soup with cream cheese and spinach that tastes absolutely decadent.','American','Easy',10,30,40,6,520,24,32,34,6,'[{"amount":1,"unit":"pound","item":"Italian ground sausage","group":"Protein"},{"amount":2,"unit":"cans","item":"white cannellini beans drained and rinsed","group":"Beans"},{"amount":4,"unit":"cups","item":"chicken broth","group":"Base"},{"amount":8,"unit":"ounces","item":"cream cheese softened and cubed","group":"Dairy"},{"amount":2,"unit":"cups","item":"fresh baby spinach","group":"Vegetables"},{"amount":1,"unit":"can","item":"diced tomatoes with juices","group":"Vegetables"},{"amount":1,"unit":"teaspoon","item":"Italian seasoning","group":"Spices"},{"amount":3,"unit":"cloves","item":"garlic minced","group":"Aromatics"}]','[{"title":"Brown the Sausage","text":"In a large heavy bottomed pot over medium high heat cook the Italian ground sausage breaking it apart with a spoon as it cooks. Continue cooking for 6 to 8 minutes until fully browned and no pink remains. Drain excess fat if necessary but leave a little for flavor.","timer":480},{"title":"Add Aromatics and Tomatoes","text":"Reduce heat to medium and add the minced garlic to the pot with the sausage. Cook for 1 minute until fragrant. Pour in the diced tomatoes with their juices and stir in the Italian seasoning. Let it simmer for 2 minutes.","timer":180},{"title":"Build the Broth","text":"Pour in the chicken broth and add the drained cannellini beans. Stir everything together and bring the soup to a gentle boil over medium high heat. Let it simmer for 8 to 10 minutes so the flavors meld together beautifully.","timer":600},{"title":"Melt in the Cream Cheese","text":"Reduce heat to low and add the cubed cream cheese to the pot. Stir continuously until the cream cheese is completely melted and incorporated into the broth creating a silky and luscious consistency. This will take about 3 to 4 minutes.","timer":240},{"title":"Finish with Spinach and Serve","text":"Add the fresh baby spinach to the pot and stir until it wilts into the soup which takes about 1 to 2 minutes. Taste and adjust seasoning with salt and pepper. Serve hot with crusty bread or dinner rolls.","timer":120}]','[{"original":"Italian ground sausage","swap":"turkey sausage or ground chicken for a lighter option"},{"original":"cream cheese","swap":"mascarpone cheese for an even richer flavor"},{"original":"fresh baby spinach","swap":"frozen spinach thawed and squeezed dry"}]','["Adding cold cream cheese directly to boiling soup which causes it to curdle rather than melt smoothly","Not draining the cannellini beans which can make the soup too starchy and thick","Overcooking the spinach by adding it too early which makes it slimy and dull in color"]','["soup","creamy","sausage","comfort food","easy","weeknight dinner","hearty","winter"]','["Gluten-Free","Nut-Free"]','Soup','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Lasagna Soup','lasagna-soup','Lasagna Soup captures all the bold cheesy and meaty flavors of classic lasagna in a warm and comforting bowl of soup. Broken lasagna noodles simmer in a rich tomato and beef broth topped with a creamy three cheese blend that melts right into every spoonful.','All the comforting flavors of classic lasagna transformed into a hearty and cheesy one-pot soup.','Italian-American','Medium',15,35,50,6,610,36,52,28,5,'[{"amount":1,"unit":"pound","item":"lean ground beef","group":"Protein"},{"amount":8,"unit":"sheets","item":"lasagna noodles broken into pieces","group":"Pasta"},{"amount":1,"unit":"can","item":"crushed tomatoes 28 ounces","group":"Base"},{"amount":4,"unit":"cups","item":"beef broth","group":"Base"},{"amount":1,"unit":"cup","item":"ricotta cheese","group":"Cheese"},{"amount":1,"unit":"cup","item":"shredded mozzarella cheese","group":"Cheese"},{"amount":2,"unit":"teaspoons","item":"Italian seasoning","group":"Spices"},{"amount":1,"unit":"medium","item":"yellow onion diced","group":"Vegetables"}]','[{"title":"Brown the Beef and Onion","text":"Heat a large Dutch oven or heavy pot over medium high heat. Add the ground beef and diced onion together and cook breaking the beef apart for 7 to 8 minutes until the beef is fully browned and the onion is softened. Drain any excess grease from the pot.","timer":480},{"title":"Build the Tomato Base","text":"Add the Italian seasoning to the browned beef and stir for 30 seconds. Pour in the crushed tomatoes and beef broth and stir everything together. Season generously with salt and pepper. Bring the mixture to a boil over medium high heat.","timer":300},{"title":"Simmer and Add Noodles","text":"Once the soup reaches a boil reduce heat to medium and add the broken lasagna noodle pieces directly to the pot. Stir well to prevent sticking. Cook uncovered for 12 to 14 minutes stirring occasionally until the noodles are tender.","timer":840},{"title":"Prepare the Cheese Mixture","text":"While the soup simmers combine the ricotta cheese and half of the shredded mozzarella in a small bowl. Mix well with a spoon until blended. This cheese mixture will be added directly to each bowl for a rich and creamy lasagna experience.","timer":120},{"title":"Serve with Cheese Topping","text":"Ladle the hot lasagna soup into bowls and immediately top each bowl with a generous dollop of the ricotta and mozzarella mixture. Sprinkle the remaining mozzarella over the top. The heat from the soup will melt the cheese into a gooey and irresistible topping.","timer":0}]','[{"original":"lean ground beef","swap":"Italian ground sausage for a more traditional lasagna flavor"},{"original":"lasagna noodles","swap":"any wide pasta such as pappardelle or broken fettuccine"},{"original":"ricotta cheese","swap":"cottage cheese blended smooth for a lighter option"}]','["Cooking the lasagna noodles separately and adding them at the end which prevents them from absorbing the rich soup flavor","Not breaking the noodles small enough which makes them difficult to eat with a spoon","Adding the cheese mixture directly to the pot rather than serving it on top which makes the soup clumpy and overly thick"]','["soup","lasagna","Italian","comfort food","pasta","cheesy","hearty","weeknight dinner","winter"]','["Nut-Free"]','Soup','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('French Onion Soup','french-onion-soup','A rich and deeply savory soup built on a foundation of slowly caramelized onions simmered in beef broth and finished with crusty bread and melted Gruyere cheese. This classic French bistro dish rewards patience with layers of sweet, umami-packed flavor in every spoonful.','Classic French soup with caramelized onions, beefy broth, and bubbling Gruyere toasts.','French','Medium',15,75,90,4,420,18,38,22,3,'[{"amount":4,"unit":"large","item":"yellow onions, thinly sliced","group":"Soup"},{"amount":4,"unit":"tbsp","item":"unsalted butter","group":"Soup"},{"amount":1,"unit":"cup","item":"dry white wine","group":"Soup"},{"amount":6,"unit":"cups","item":"beef broth","group":"Soup"},{"amount":2,"unit":"tsp","item":"fresh thyme leaves","group":"Soup"},{"amount":8,"unit":"slices","item":"baguette, cut 1 inch thick","group":"Topping"},{"amount":2,"unit":"cups","item":"Gruyere cheese, shredded","group":"Topping"},{"amount":1,"unit":"tsp","item":"salt and black pepper","group":"Seasoning"}]','[{"title":"Caramelize the Onions","text":"Melt butter in a large heavy-bottomed pot over medium heat. Add all the sliced onions and a pinch of salt, stirring to coat. Cook low and slow for 45 to 55 minutes, stirring every 5 to 8 minutes, until the onions are deep golden brown and very soft. Do not rush this step as proper caramelization builds the entire flavor base of the soup.","timer":3300},{"title":"Deglaze and Build the Broth","text":"Increase heat to medium-high and pour in the white wine. Scrape up any browned bits stuck to the bottom of the pot. Let the wine reduce by half, about 3 minutes, then add the beef broth and fresh thyme. Bring to a gentle boil, then reduce heat and simmer for 15 minutes to meld the flavors together.","timer":1080},{"title":"Season the Soup","text":"Taste the soup and adjust seasoning with salt and black pepper as needed. The broth should be rich, savory, and slightly sweet from the onions. Remove the thyme sprigs if using whole sprigs and keep the soup warm on low heat while you prepare the cheese toasts.","timer":120},{"title":"Toast the Baguette Slices","text":"Place baguette slices on a baking sheet and broil for 2 to 3 minutes per side until golden and crisp. This toasting step is important because it prevents the bread from becoming completely soggy when placed on top of the soup. Remove from oven and set aside.","timer":300},{"title":"Assemble and Broil","text":"Ladle the hot soup into oven-safe crocks or bowls placed on a baking sheet. Float two toasted baguette slices on top of each bowl and cover generously with shredded Gruyere cheese. Place under the broiler for 3 to 5 minutes until the cheese is melted, bubbly, and spotted with golden brown patches. Serve immediately and warn guests that the bowls are extremely hot.","timer":300}]','[{"original":"Gruyere cheese","swap":"Swiss cheese or Emmental for a milder but equally melty topping"},{"original":"dry white wine","swap":"additional beef broth with a splash of apple cider vinegar to add acidity"},{"original":"beef broth","swap":"vegetable broth with a tablespoon of soy sauce for a vegetarian version with depth"}]','["Rushing the caramelization process by using high heat, which burns the onions instead of developing deep sweetness","Using pre-shredded cheese which contains anti-caking agents that prevent proper melting and browning under the broiler","Skipping the toasting step for the baguette, resulting in bread that completely dissolves into the soup before it reaches the table"]','["soup","french","onion","comfort food","winter","cheese","classic","bistro"]','["vegetarian-adaptable"]','Soup','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Tuscan White Bean Kale Soup','tuscan-white-bean-kale-soup','A hearty and nourishing Italian-inspired soup that combines creamy cannellini beans, earthy kale, and fragrant rosemary in a lightly tomato-kissed broth. This wholesome one-pot meal is naturally filling, packed with plant-based protein, and comes together in under 40 minutes on a busy weeknight.','Hearty Italian-style soup with creamy white beans, tender kale, and aromatic herbs.','Italian','Easy',10,30,40,6,310,15,42,8,11,'[{"amount":2,"unit":"cans","item":"cannellini beans, drained and rinsed","group":"Soup"},{"amount":4,"unit":"cups","item":"curly kale, stems removed and roughly chopped","group":"Soup"},{"amount":1,"unit":"can","item":"diced tomatoes","group":"Soup"},{"amount":5,"unit":"cups","item":"vegetable broth","group":"Soup"},{"amount":4,"unit":"cloves","item":"garlic, minced","group":"Aromatics"},{"amount":1,"unit":"medium","item":"yellow onion, diced","group":"Aromatics"},{"amount":2,"unit":"tbsp","item":"olive oil","group":"Aromatics"},{"amount":1,"unit":"tsp","item":"dried rosemary and red pepper flakes","group":"Seasoning"}]','[{"title":"Saute the Aromatics","text":"Heat olive oil in a large pot over medium heat. Add the diced onion and cook for 5 to 6 minutes until softened and translucent. Add the minced garlic, dried rosemary, and red pepper flakes, stirring constantly for 1 minute until fragrant. This aromatic base gives the soup its distinctly Tuscan character and should not be skipped or shortened.","timer":420},{"title":"Add Tomatoes and Broth","text":"Pour in the diced tomatoes with all their juices and stir to combine with the aromatics. Let the tomatoes cook for 2 minutes to slightly concentrate their flavor, then pour in the vegetable broth. Increase heat to bring the soup to a boil, then reduce to a steady simmer.","timer":300},{"title":"Simmer the Beans","text":"Add the drained cannellini beans to the simmering broth. Using the back of a wooden spoon or a potato masher, lightly crush about one quarter of the beans directly in the pot. This thickens the broth naturally and gives the soup a creamy, velvety body without any added cream or flour. Simmer for 10 minutes.","timer":600},{"title":"Wilt the Kale","text":"Add the chopped kale to the pot and stir it into the hot broth. Cook for 5 to 7 minutes until the kale is tender and has wilted down significantly. Tuscan kale also known as lacinato or dinosaur kale can be used for a more authentic texture and slightly less bitter flavor than curly kale.","timer":420},{"title":"Season and Serve","text":"Taste the soup and season generously with salt and black pepper. Ladle into bowls and finish each serving with a drizzle of good quality olive oil and a sprinkle of Parmesan cheese if desired. The soup thickens considerably as it sits, so add a splash of broth when reheating leftovers to restore the right consistency.","timer":60}]','[{"original":"cannellini beans","swap":"great northern beans or navy beans which have a similarly creamy texture and mild flavor"},{"original":"kale","swap":"baby spinach stirred in at the very end of cooking for a more delicate green that wilts quickly"},{"original":"vegetable broth","swap":"chicken broth for a richer non-vegetarian version with deeper savory notes"}]','["Adding the kale too early in the cooking process which causes it to become mushy and lose its vibrant green color and nutritional value","Skipping the step of mashing some of the beans, resulting in a thin watery broth instead of the characteristically thick and creamy Tuscan texture","Under-seasoning the soup, since beans and kale both require generous salt to bring out their flavors and the broth can taste flat without proper seasoning"]','["soup","italian","tuscan","beans","kale","vegetarian","healthy","weeknight","one-pot"]','["vegetarian","vegan","gluten-free","dairy-free"]','Soup','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Slow Cooker Texas Chili','slow-cooker-texas-chili','A bold and fiercely beefy Texas-style chili featuring chunks of chuck roast slow-cooked in a complex dried chile sauce with absolutely no beans and no tomato chunks allowed. This no-compromise bowl of red develops incredible depth over hours in the slow cooker, delivering smoky, spicy, and richly savory flavor that defines authentic Lone Star chili tradition.','Bold beanless Texas chili with chunks of beef and a deep dried chile sauce made low and slow.','American','Medium',20,480,500,8,510,42,12,28,3,'[{"amount":3,"unit":"lbs","item":"beef chuck roast, cut into 1 inch cubes","group":"Protein"},{"amount":3,"unit":"tbsp","item":"ancho chile powder","group":"Spice Blend"},{"amount":2,"unit":"tbsp","item":"cumin","group":"Spice Blend"},{"amount":1,"unit":"can","item":"crushed tomatoes","group":"Base"},{"amount":1,"unit":"cup","item":"beef broth","group":"Base"},{"amount":4,"unit":"cloves","item":"garlic, minced","group":"Aromatics"},{"amount":1,"unit":"large","item":"white onion, diced","group":"Aromatics"},{"amount":2,"unit":"tbsp","item":"vegetable oil","group":"Cooking"}]','[{"title":"Sear the Beef in Batches","text":"Pat the chuck roast cubes completely dry with paper towels and season generously with salt and black pepper. Heat vegetable oil in a large skillet over high heat until shimmering. Sear the beef in two or three batches for 2 to 3 minutes per side until deeply browned on all surfaces. Do not crowd the pan as overcrowding causes the beef to steam instead of sear, and that browned crust carries enormous flavor for the final chili.","timer":900},{"title":"Saute Aromatics and Bloom Spices","text":"In the same skillet with the remaining beef fat, reduce heat to medium and add the diced onion. Cook for 4 to 5 minutes until softened, then add the garlic and cook for 1 more minute. Add the ancho chile powder and cumin directly to the skillet and stir constantly for 45 seconds to bloom the spices in the fat. This activates the fat-soluble flavor compounds in the dried chiles and makes the spice flavor significantly more vibrant and complex.","timer":420},{"title":"Build the Slow Cooker Base","text":"Transfer the seared beef to the slow cooker insert. Pour the onion, garlic, and bloomed spice mixture over the beef. Add the crushed tomatoes and beef broth, stirring gently to distribute everything evenly. The liquid should come about halfway up the beef, as the meat will release its own juices during the long cook and the chili will concentrate and thicken naturally.","timer":120},{"title":"Slow Cook Low and Slow","text":"Set the slow cooker to low and cook for 8 hours without lifting the lid. Resist the urge to check on the chili frequently as each time you lift the lid you release steam and add roughly 20 to 30 minutes to the required cooking time. After 8 hours the beef should be fork-tender and beginning to pull apart slightly while still holding its chunky shape.","timer":28800},{"title":"Finish and Adjust","text":"Remove the lid and use a large spoon to skim any excess fat from the surface of the chili. Taste and adjust salt, cumin, and chile powder as needed. If the chili is thinner than you prefer, leave the lid off and cook on high for an additional 20 to 30 minutes to reduce. Serve in bowls topped with shredded cheddar, diced white onion, sour cream, and pickled jalapenos for the full Texas experience.","timer":1800}]','[{"original":"ancho chile powder","swap":"a blend of regular chili powder and a small amount of chipotle powder for smokier heat"},{"original":"beef chuck roast","swap":"beef brisket cut into cubes which becomes equally tender and has slightly more fat for richness"},{"original":"crushed tomatoes","swap":"tomato paste diluted with additional beef broth for a less prominent tomato flavor more true to strict Texas tradition"}]','["Skipping the searing step and adding raw beef directly to the slow cooker, which results in gray flavorless meat and a thin broth lacking the deep savory foundation that browning provides","Adding beans to the chili, which is a serious departure from authentic Texas chili tradition and changes the texture and flavor profile significantly","Cooking on the high setting to save time, which causes the beef to become stringy and dry rather than developing the meltingly tender chunks that define a great bowl of Texas red"]','["chili","texas","beef","slow cooker","beanless","spicy","comfort food","game day","american","fall","winter"]','["gluten-free","dairy-free"]','Stew','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Chicken Tortilla Soup','chicken-tortilla-soup','This bold and hearty Chicken Tortilla Soup is packed with tender shredded chicken, black beans, and fire-roasted tomatoes in a smoky spiced broth. It is topped with crispy tortilla strips, shredded cheese, and creamy avocado for the ultimate comforting bowl.','A smoky and spicy chicken soup loaded with beans and topped with crunchy tortilla strips.','Mexican','Easy',10,30,40,6,320,28,34,9,7,'[{"amount":1.5,"unit":"lbs","item":"boneless skinless chicken breasts","group":"Protein"},{"amount":1,"unit":"can","item":"fire-roasted diced tomatoes","group":"Base"},{"amount":1,"unit":"can","item":"black beans, drained and rinsed","group":"Base"},{"amount":1,"unit":"can","item":"corn kernels, drained","group":"Base"},{"amount":4,"unit":"cups","item":"low-sodium chicken broth","group":"Base"},{"amount":2,"unit":"tsp","item":"chili powder","group":"Seasoning"},{"amount":1,"unit":"tsp","item":"ground cumin","group":"Seasoning"},{"amount":6,"unit":"small","item":"corn tortillas, cut into strips","group":"Topping"}]','[{"title":"Build the Broth","text":"Add chicken broth, fire-roasted tomatoes, black beans, corn, chili powder, and cumin to a large pot over medium-high heat. Stir well to combine all the ingredients and bring the mixture to a gentle boil.","timer":600},{"title":"Cook the Chicken","text":"Add the whole chicken breasts directly into the simmering broth. Reduce heat to medium and cook the chicken until it is completely cooked through and reaches an internal temperature of 165 degrees F.","timer":1200},{"title":"Shred the Chicken","text":"Remove the cooked chicken breasts from the pot and place them on a cutting board. Use two forks to shred the chicken into bite-sized pieces, then return the shredded chicken back into the soup pot.","timer":300},{"title":"Crisp the Tortilla Strips","text":"While the soup simmers, spread the tortilla strips on a baking sheet and bake at 400 degrees F for 8 to 10 minutes until they are golden and crispy. Alternatively you can pan-fry them in a small amount of oil until crunchy.","timer":600},{"title":"Serve and Top","text":"Ladle the hot soup into bowls and top each serving generously with the crispy tortilla strips. Add desired toppings such as shredded cheese, sour cream, diced avocado, and fresh cilantro before serving immediately.","timer":120}]','[{"original":"chicken breasts","swap":"rotisserie chicken, shredded and added at the end"},{"original":"black beans","swap":"pinto beans or kidney beans"},{"original":"corn tortillas","swap":"store-bought tortilla chips for quick topping"}]','["Overcooking the chicken in the broth which makes it dry and tough rather than tender","Skipping the fire-roasted tomatoes and using plain diced tomatoes which reduces the smoky depth of flavor","Adding tortilla strips directly into the soup too early which causes them to become soggy instead of staying crispy"]','["soup","chicken","mexican","tortilla","spicy","weeknight","comfort food"]','["Gluten-Free","Dairy-Free"]','Soup','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Stuffed Pepper Soup','stuffed-pepper-soup','This Stuffed Pepper Soup captures all the classic flavors of traditional stuffed bell peppers in a warm and satisfying one-pot soup. Tender ground beef, colorful bell peppers, rice, and a rich tomato broth come together for a hearty and easy weeknight meal.','All the flavors of classic stuffed peppers transformed into a cozy and easy one-pot soup.','American','Easy',15,35,50,6,355,24,38,11,5,'[{"amount":1,"unit":"lb","item":"lean ground beef","group":"Protein"},{"amount":3,"unit":"medium","item":"bell peppers, diced (mixed colors)","group":"Vegetables"},{"amount":1,"unit":"medium","item":"yellow onion, diced","group":"Vegetables"},{"amount":2,"unit":"cans","item":"diced tomatoes with juice","group":"Base"},{"amount":4,"unit":"cups","item":"beef broth","group":"Base"},{"amount":1,"unit":"cup","item":"long-grain white rice, uncooked","group":"Grains"},{"amount":2,"unit":"tsp","item":"Italian seasoning","group":"Seasoning"},{"amount":1,"unit":"tsp","item":"garlic powder","group":"Seasoning"}]','[{"title":"Brown the Beef","text":"Heat a large pot or Dutch oven over medium-high heat. Add the ground beef and cook, breaking it apart with a wooden spoon, until it is fully browned and no pink remains. Drain any excess fat from the pot before continuing.","timer":480},{"title":"Soften the Vegetables","text":"Add the diced onion and bell peppers to the pot with the browned beef. Cook over medium heat, stirring occasionally, until the onion becomes translucent and the peppers begin to soften slightly, about 5 minutes.","timer":300},{"title":"Build the Soup Base","text":"Pour in the diced tomatoes with their juice and the beef broth. Stir in the Italian seasoning and garlic powder. Increase the heat to medium-high and bring the soup to a full boil, stirring occasionally to prevent sticking.","timer":480},{"title":"Cook the Rice","text":"Once the soup is boiling, stir in the uncooked white rice. Reduce the heat to medium-low, cover the pot with a lid, and let the soup simmer until the rice is fully cooked and tender, about 18 to 20 minutes.","timer":1200},{"title":"Adjust and Serve","text":"Taste the soup and adjust the seasoning with salt and black pepper as needed. Ladle into bowls and serve hot with crusty bread or a sprinkle of shredded mozzarella or Parmesan cheese on top.","timer":120}]','[{"original":"lean ground beef","swap":"ground turkey or ground chicken for a lighter option"},{"original":"white rice","swap":"cauliflower rice stirred in at the end for a lower-carb version"},{"original":"beef broth","swap":"vegetable broth for a lighter and less rich flavor"}]','["Adding the rice too early before the broth comes to a boil which results in unevenly cooked and mushy rice","Not draining the fat after browning the beef which makes the soup greasy and heavy","Overcooking the soup after the rice is done which causes the rice to absorb too much broth and become overly thick"]','["soup","beef","stuffed peppers","rice","comfort food","one-pot","weeknight"]','["Gluten-Free","Dairy-Free"]','Soup','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Creamy Potato Soup','creamy-potato-soup','This ultra-creamy and velvety Potato Soup is made with tender chunks of russet potatoes simmered in a rich and savory broth that is blended to perfection. Finished with sharp cheddar cheese, crispy bacon, and fresh chives, it is the ultimate loaded comfort food experience.','A thick and velvety potato soup loaded with cheddar, bacon, and chives for pure comfort.','American','Medium',15,35,50,6,410,14,48,19,4,'[{"amount":2.5,"unit":"lbs","item":"russet potatoes, peeled and diced","group":"Base"},{"amount":1,"unit":"medium","item":"yellow onion, diced","group":"Vegetables"},{"amount":4,"unit":"cups","item":"low-sodium chicken broth","group":"Base"},{"amount":1,"unit":"cup","item":"whole milk","group":"Dairy"},{"amount":0.5,"unit":"cup","item":"sour cream","group":"Dairy"},{"amount":1.5,"unit":"cups","item":"shredded sharp cheddar cheese","group":"Dairy"},{"amount":6,"unit":"strips","item":"bacon, cooked and crumbled","group":"Topping"},{"amount":3,"unit":"tbsp","item":"unsalted butter","group":"Base"}]','[{"title":"Saute the Onion","text":"Melt the butter in a large heavy-bottomed pot over medium heat. Add the diced onion and cook, stirring frequently, until it becomes soft and translucent and begins to turn golden around the edges, about 5 to 6 minutes.","timer":360},{"title":"Simmer the Potatoes","text":"Add the diced potatoes and chicken broth to the pot. Increase heat to medium-high and bring everything to a boil. Reduce to a steady simmer and cook uncovered until the potatoes are very tender and easily pierced with a fork.","timer":1200},{"title":"Blend for Creaminess","text":"Use an immersion blender to partially blend the soup directly in the pot, leaving some potato chunks for texture. Alternatively transfer about half the soup to a blender, blend until smooth, and return it to the pot for a chunky yet creamy result.","timer":180},{"title":"Finish with Dairy","text":"Reduce the heat to low and stir in the whole milk and sour cream until fully incorporated. Do not allow the soup to boil after adding the dairy as this can cause it to curdle. Stir in half of the shredded cheddar cheese until melted and smooth.","timer":300},{"title":"Season and Serve","text":"Season the soup generously with salt and black pepper to taste. Ladle into bowls and top each serving with the remaining shredded cheddar, crumbled bacon, and fresh chives or green onion slices. Serve immediately while hot.","timer":120}]','[{"original":"russet potatoes","swap":"Yukon Gold potatoes for a naturally creamier and more buttery texture"},{"original":"sour cream","swap":"plain full-fat Greek yogurt for a tangy and lighter alternative"},{"original":"whole milk","swap":"heavy cream for an even richer and more indulgent soup"}]','["Boiling the soup after adding the sour cream or milk which causes the dairy to separate and curdle","Under-seasoning the soup since potatoes absorb a large amount of salt and need generous seasoning","Blending the entire soup completely smooth which removes all texture and makes the consistency more like a puree than a satisfying chunky soup"]','["soup","potato","creamy","comfort food","cheddar","bacon","winter"]','["Gluten-Free"]','Soup','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Famous Indian Butter Chicken','famous-indian-butter-chicken','This iconic Indian dish features tender chicken pieces simmered in a rich, creamy tomato-based sauce infused with warming spices. It is a beloved comfort food that delivers deep, complex flavors with every bite.','Creamy, spiced tomato sauce coats tender chicken in this classic Indian restaurant favorite.','Indian','Medium',20,40,60,4,520,38,14,34,3,'[{"amount":700,"unit":"g","item":"boneless chicken thighs cut into chunks","group":"Chicken"},{"amount":1,"unit":"cup","item":"plain full-fat yogurt","group":"Marinade"},{"amount":2,"unit":"tbsp","item":"garam masala","group":"Spices"},{"amount":400,"unit":"g","item":"canned crushed tomatoes","group":"Sauce"},{"amount":1,"unit":"cup","item":"heavy cream","group":"Sauce"},{"amount":4,"unit":"tbsp","item":"unsalted butter","group":"Sauce"},{"amount":1,"unit":"tbsp","item":"fresh ginger paste","group":"Aromatics"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"Aromatics"}]','[{"title":"Marinate the Chicken","text":"Combine yogurt, half the garam masala, ginger paste, and half the garlic in a large bowl. Add chicken pieces and coat thoroughly. Cover and marinate for at least 30 minutes or overnight in the refrigerator for best results.","timer":1800},{"title":"Cook the Chicken","text":"Heat a large skillet or grill pan over high heat. Cook the marinated chicken pieces for 4 to 5 minutes per side until slightly charred and cooked through. Set aside on a plate.","timer":600},{"title":"Build the Sauce","text":"In the same pan, melt butter over medium heat. Add remaining garlic and cook for 1 minute until fragrant. Pour in the crushed tomatoes and remaining garam masala. Simmer for 15 minutes stirring occasionally until the sauce thickens and deepens in color.","timer":900},{"title":"Combine and Simmer","text":"Add the cooked chicken pieces into the tomato sauce and stir to coat. Pour in the heavy cream and reduce heat to low. Simmer gently for 10 minutes allowing the chicken to absorb all the flavors from the sauce.","timer":600},{"title":"Finish and Serve","text":"Taste and adjust salt as needed. Garnish with a swirl of cream and fresh cilantro if desired. Serve hot with steamed basmati rice or warm naan bread for a complete and satisfying meal.","timer":0}]','[{"original":"heavy cream","swap":"full-fat coconut milk for a dairy-free version"},{"original":"boneless chicken thighs","swap":"boneless chicken breasts for a leaner option"},{"original":"plain yogurt","swap":"dairy-free coconut yogurt for a vegan marinade"}]','["Skipping the marination step which results in dry and flavorless chicken","Adding cream over high heat which causes the sauce to curdle and separate","Not simmering the tomato sauce long enough leaving a raw acidic taste"]','["butter chicken","Indian","curry","creamy","comfort food","chicken","spiced"]','["Gluten-Free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Korean Gochujang Fried Chicken','korean-gochujang-fried-chicken','This Korean-style fried chicken is coated in a fiery, sticky gochujang glaze that delivers an irresistible combination of heat, sweetness, and umami. The double-fry technique ensures an ultra-crispy exterior that holds up beautifully under the bold sauce.','Crispy double-fried chicken coated in a bold and sticky Korean gochujang sauce.','Korean','Medium',25,35,60,4,610,42,38,30,2,'[{"amount":1,"unit":"kg","item":"bone-in chicken pieces drumsticks and wings","group":"Chicken"},{"amount":1,"unit":"cup","item":"cornstarch","group":"Coating"},{"amount":3,"unit":"tbsp","item":"gochujang Korean chili paste","group":"Sauce"},{"amount":2,"unit":"tbsp","item":"soy sauce","group":"Sauce"},{"amount":2,"unit":"tbsp","item":"honey","group":"Sauce"},{"amount":1,"unit":"tbsp","item":"sesame oil","group":"Sauce"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"Sauce"},{"amount":4,"unit":"cups","item":"neutral oil for deep frying","group":"Frying"}]','[{"title":"Prepare and Coat the Chicken","text":"Pat chicken pieces completely dry with paper towels to remove all moisture. Season generously with salt and pepper. Toss each piece in cornstarch pressing firmly to ensure a thorough and even coating on all surfaces.","timer":0},{"title":"First Fry","text":"Heat oil in a deep pot or Dutch oven to 160 degrees Celsius. Fry the chicken pieces in batches for 8 minutes per batch. Do not overcrowd the pot. Remove chicken and drain on a wire rack. Allow to rest for 5 minutes.","timer":480},{"title":"Second Fry","text":"Increase oil temperature to 190 degrees Celsius. Fry the chicken pieces again for 3 to 4 minutes until deeply golden and extra crispy. This second fry is the secret to achieving that signature shattering crunch.","timer":240},{"title":"Make the Gochujang Glaze","text":"In a small saucepan over medium heat combine gochujang, soy sauce, honey, sesame oil, and garlic. Stir continuously for 3 minutes until the sauce thickens slightly and becomes fragrant. Do not let it burn.","timer":180},{"title":"Toss and Serve","text":"Working quickly while the chicken is still hot, toss the fried pieces in the gochujang glaze until every piece is evenly coated and glistening. Transfer to a serving platter and garnish with toasted sesame seeds and sliced green onions.","timer":0}]','[{"original":"gochujang","swap":"sriracha mixed with a pinch of miso paste for a similar depth of heat"},{"original":"honey","swap":"maple syrup for a slightly different sweetness profile"},{"original":"cornstarch","swap":"potato starch for an even crispier and lighter coating"}]','["Not drying the chicken thoroughly before coating which prevents proper crispiness","Skipping the second fry which is essential for achieving the signature Korean fried chicken crunch","Tossing the chicken in sauce too early while it is still draining causing the coating to go soggy"]','["Korean fried chicken","gochujang","spicy","crispy","Korean","fried chicken","sticky glaze"]','["Dairy-Free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Pastel de Nata','pastel-de-nata','Pastel de Nata is a legendary Portuguese egg tart featuring a flaky, buttery puff pastry shell filled with a silky, lightly caramelized custard cream. Originating from the Jeronimos Monastery in Lisbon, these tarts are best enjoyed warm with a dusting of cinnamon.','Flaky Portuguese custard tarts with a caramelized top and creamy egg filling.','Portuguese','Hard',40,20,60,12,210,5,24,11,1,'[{"amount":1,"unit":"sheet","item":"store-bought puff pastry thawed","group":"Pastry"},{"amount":6,"unit":"large","item":"egg yolks","group":"Custard"},{"amount":200,"unit":"g","item":"white granulated sugar","group":"Custard"},{"amount":500,"unit":"ml","item":"whole milk","group":"Custard"},{"amount":3,"unit":"tbsp","item":"all-purpose flour","group":"Custard"},{"amount":1,"unit":"tsp","item":"pure vanilla extract","group":"Custard"},{"amount":1,"unit":"stick","item":"cinnamon","group":"Custard"},{"amount":1,"unit":"strip","item":"lemon zest","group":"Custard"}]','[{"title":"Prepare the Pastry Shells","text":"Preheat oven to 250 degrees Celsius or as high as your oven will go. Roll the puff pastry sheet tightly into a log and cut into 12 equal discs. Press each disc into a greased muffin tin using your thumbs to form a thin cup shape going all the way up the sides.","timer":0},{"title":"Make the Custard Base","text":"In a small saucepan combine sugar, cinnamon stick, lemon zest, and 100 ml of water. Bring to a boil and cook for 2 minutes until a light syrup forms. Remove cinnamon and lemon. In a separate bowl whisk flour with 100 ml of cold milk until smooth, then add remaining milk and stir to combine.","timer":120},{"title":"Cook the Custard","text":"Pour the milk and flour mixture into a saucepan over medium heat. Cook stirring constantly for 5 minutes until it thickens to a pudding-like consistency. Remove from heat and slowly stream in the hot sugar syrup while stirring vigorously. Add vanilla extract and allow to cool for 5 minutes.","timer":300},{"title":"Add Egg Yolks and Fill","text":"Whisk the egg yolks into the cooled custard mixture one at a time until fully incorporated and smooth. Strain the custard through a fine mesh sieve for extra silkiness. Fill each prepared pastry shell about three-quarters full with the custard mixture.","timer":0},{"title":"Bake Until Caramelized","text":"Bake the tarts at 250 degrees Celsius for 15 to 18 minutes until the custard is set with dark, blistered caramel spots on top and the pastry is deeply golden. The caramelized spots are characteristic and essential to authentic Pastel de Nata. Allow to cool slightly before serving with ground cinnamon.","timer":1080}]','[{"original":"store-bought puff pastry","swap":"homemade rough puff pastry for a more traditional and flaky result"},{"original":"whole milk","swap":"full-fat oat milk for a dairy-free version though the custard will be slightly less rich"},{"original":"all-purpose flour","swap":"cornstarch for a slightly smoother and more translucent custard texture"}]','["Baking at too low a temperature which prevents the signature caramelized dark spots from forming on the custard","Filling the pastry shells too full causing the custard to overflow and stick to the tin during baking","Adding egg yolks to the custard while it is still too hot which scrambles the eggs and ruins the smooth texture"]','["pastel de nata","Portuguese","custard tart","egg tart","baking","dessert","pastry"]','["Vegetarian"]','Dessert','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Italian Carbonara','italian-carbonara','A classic Roman pasta dish made with eggs, cheese, cured pork, and black pepper that creates a rich and creamy sauce without any cream. This indulgent recipe relies on technique and quality ingredients to achieve its signature silky texture.','A rich and silky Roman pasta dish made with eggs, guanciale, and Pecorino Romano cheese.','Italian','Medium',10,20,30,4,620,28,72,24,3,'[{"amount":400,"unit":"g","item":"spaghetti","group":"Pasta"},{"amount":200,"unit":"g","item":"guanciale cut into small cubes","group":"Protein"},{"amount":4,"unit":"whole","item":"large eggs","group":"Sauce"},{"amount":100,"unit":"g","item":"Pecorino Romano finely grated","group":"Sauce"},{"amount":2,"unit":"tsp","item":"freshly ground black pepper","group":"Seasoning"},{"amount":1,"unit":"tsp","item":"fine sea salt","group":"Seasoning"},{"amount":50,"unit":"g","item":"Parmesan finely grated","group":"Sauce"},{"amount":60,"unit":"ml","item":"reserved pasta cooking water","group":"Sauce"}]','[{"title":"Cook the Guanciale","text":"Place the guanciale cubes in a cold skillet and turn the heat to medium. Cook slowly for 8 to 10 minutes until the fat renders and the meat turns golden and slightly crispy. Remove the pan from heat and set aside, keeping the rendered fat in the pan.","timer":600},{"title":"Boil the Pasta","text":"Bring a large pot of salted water to a rolling boil. Add the spaghetti and cook until just al dente according to package instructions, usually 8 to 10 minutes. Before draining, reserve at least 250ml of starchy pasta water.","timer":600},{"title":"Prepare the Egg Mixture","text":"While the pasta cooks, whisk together the eggs, grated Pecorino Romano, and grated Parmesan in a bowl until smooth. Add a generous amount of freshly ground black pepper and mix well. The mixture should be thick and uniform.","timer":120},{"title":"Combine Pasta and Guanciale","text":"Add the drained spaghetti directly into the skillet with the guanciale over very low heat. Toss well so the pasta absorbs the rendered fat. Add 60ml of the reserved pasta water and toss again for one minute.","timer":60},{"title":"Add the Egg Sauce and Finish","text":"Remove the skillet from heat completely. Pour the egg and cheese mixture over the pasta and toss rapidly and continuously, adding more pasta water a splash at a time to loosen the sauce. The residual heat will cook the eggs into a creamy sauce without scrambling them. Serve immediately with extra Pecorino and black pepper.","timer":90}]','[{"original":"guanciale","swap":"pancetta or thick-cut bacon"},{"original":"Pecorino Romano","swap":"Parmesan or a blend of both"},{"original":"spaghetti","swap":"rigatoni or bucatini"}]','["Adding the egg mixture while the pan is still on high heat which causes scrambled eggs instead of a creamy sauce","Skipping the pasta water which is essential for achieving the correct silky consistency","Using pre-grated cheese from a package which contains anti-caking agents that prevent the sauce from melting smoothly"]','["pasta","roman","classic","comfort food","weeknight dinner","creamy","no cream"]','["Dairy-Free Optional"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Jamaican Jerk Chicken Wings','jamaican-jerk-chicken-wings','These boldly flavored chicken wings are marinated in a fiery and aromatic jerk seasoning paste made with Scotch bonnet peppers, allspice, thyme, and warm spices. Grilled or baked to perfection, they deliver an authentic taste of Jamaica with smoky, spicy, and slightly sweet notes.','Fiery and aromatic Jamaican jerk chicken wings marinated in a bold blend of Scotch bonnet peppers and warm spices.','Jamaican','Easy',20,40,60,4,480,34,8,33,2,'[{"amount":1.2,"unit":"kg","item":"chicken wings split at the joint","group":"Protein"},{"amount":3,"unit":"whole","item":"Scotch bonnet peppers seeds removed","group":"Marinade"},{"amount":6,"unit":"cloves","item":"garlic","group":"Marinade"},{"amount":3,"unit":"tbsp","item":"ground allspice","group":"Marinade"},{"amount":2,"unit":"tbsp","item":"fresh thyme leaves","group":"Marinade"},{"amount":3,"unit":"tbsp","item":"soy sauce","group":"Marinade"},{"amount":2,"unit":"tbsp","item":"brown sugar","group":"Marinade"},{"amount":2,"unit":"tbsp","item":"neutral oil","group":"Marinade"}]','[{"title":"Make the Jerk Marinade","text":"Combine the Scotch bonnet peppers, garlic, allspice, thyme, soy sauce, brown sugar, and oil in a blender or food processor. Blend until a smooth paste forms. Taste carefully and adjust seasoning if needed. The marinade should be intensely fragrant and spicy.","timer":180},{"title":"Marinate the Wings","text":"Pat the chicken wings completely dry with paper towels. Place them in a large zip-lock bag or bowl and pour the jerk marinade over them. Toss thoroughly to coat every piece. Seal and refrigerate for a minimum of 4 hours, preferably overnight for maximum flavor penetration.","timer":14400},{"title":"Preheat and Prepare","text":"Remove the wings from the refrigerator 30 minutes before cooking to take the chill off. Preheat your oven to 220 degrees Celsius or heat a grill to medium-high. Line a baking sheet with foil and place a wire rack on top if baking.","timer":1800},{"title":"Cook the Wings","text":"Arrange the wings in a single layer on the wire rack or grill grates. Bake for 35 to 40 minutes, flipping once halfway through, until the skin is charred at the edges and the internal temperature reaches 74 degrees Celsius. If grilling, cook for 10 to 12 minutes per side.","timer":2400},{"title":"Rest and Serve","text":"Allow the wings to rest for 5 minutes before serving. This lets the juices redistribute throughout the meat. Serve with a cooling side such as mango salsa, coleslaw, or rice and peas to balance the heat.","timer":300}]','[{"original":"Scotch bonnet peppers","swap":"habanero peppers for a similar heat level"},{"original":"fresh thyme","swap":"dried thyme using half the amount"},{"original":"soy sauce","swap":"coconut aminos for a gluten free option"}]','["Not marinating long enough which results in flavor that only penetrates the surface of the meat","Overcrowding the baking sheet which steams the wings instead of allowing them to char properly","Removing seeds from all the peppers which eliminates too much heat and reduces the authentic jerk character"]','["wings","spicy","grilled","party food","caribbean","bold flavors","game day"]','["Gluten-Free Optional","Dairy-Free"]','Appetizer','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Japanese Souffle Pancakes','japanese-souffle-pancakes','These incredibly tall and jiggly Japanese souffle pancakes are made by folding stiffly beaten meringue into a light batter, creating an airy and cloud-like texture unlike any traditional pancake. Cooked slowly over very low heat with a lid, they rise dramatically and deliver a soft and custardy interior that is truly extraordinary.','Ultra-fluffy and jiggly Japanese souffle pancakes with a cloud-like texture achieved through carefully folded meringue.','Japanese','Hard',20,20,40,2,310,11,38,12,1,'[{"amount":2,"unit":"whole","item":"large eggs separated into yolks and whites","group":"Batter"},{"amount":30,"unit":"g","item":"all-purpose flour sifted","group":"Batter"},{"amount":20,"unit":"ml","item":"whole milk","group":"Batter"},{"amount":1,"unit":"tsp","item":"vanilla extract","group":"Batter"},{"amount":40,"unit":"g","item":"granulated sugar","group":"Meringue"},{"amount":0.5,"unit":"tsp","item":"cream of tartar","group":"Meringue"},{"amount":1,"unit":"tsp","item":"neutral oil for greasing","group":"Cooking"},{"amount":15,"unit":"ml","item":"water for steaming","group":"Cooking"}]','[{"title":"Prepare the Yolk Batter","text":"In a medium bowl, whisk together the egg yolks, milk, and vanilla extract until combined. Sift in the all-purpose flour and whisk gently until just smooth with no lumps remaining. Do not overmix. Set the bowl aside while you prepare the meringue.","timer":180},{"title":"Whip the Meringue","text":"In a clean and completely grease-free bowl, add the egg whites and cream of tartar. Beat with a hand mixer on medium speed until foamy. Gradually add the granulated sugar one tablespoon at a time while increasing to high speed. Beat until stiff and glossy peaks form that hold their shape when the beaters are lifted.","timer":300},{"title":"Fold and Combine","text":"Add one third of the meringue to the yolk batter and gently stir to lighten the mixture. Add the remaining meringue in two additions, folding slowly with a spatula using a large J-shaped motion from the bottom of the bowl upward. Stop folding as soon as no white streaks remain to preserve as much air as possible.","timer":120},{"title":"Cook the Pancakes","text":"Lightly grease a non-stick skillet with oil and heat over the lowest possible flame. Spoon the batter into two tall mounds using a large spoon or ring molds if available. Add the water to the edge of the pan and immediately cover with a lid. Cook for 7 to 8 minutes until the bottoms are set and lightly golden.","timer":480},{"title":"Flip and Finish","text":"Very carefully slide a thin spatula under each pancake and flip gently in one smooth motion. Replace the lid and cook for another 5 to 6 minutes until the pancakes are cooked through and spring back lightly when touched. Transfer to plates immediately and serve with maple syrup, whipped cream, or fresh berries.","timer":360}]','[{"original":"cream of tartar","swap":"a few drops of fresh lemon juice to stabilize the meringue"},{"original":"all-purpose flour","swap":"cake flour for an even more tender texture"},{"original":"whole milk","swap":"oat milk or almond milk for a dairy free version"}]','["Getting any yolk or grease into the egg whites which prevents the meringue from whipping to stiff peaks","Cooking over heat that is too high which sets the outside before the inside is cooked and causes collapse","Deflating the batter by overmixing when folding the meringue which destroys the air bubbles responsible for the height"]','["pancakes","fluffy","breakfast","brunch","japanese","airy","cafe style","instagram worthy"]','["Vegetarian"]','Breakfast','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Spanish Seafood Paella','spanish-seafood-paella','This classic Spanish Seafood Paella brings together saffron-infused rice with fresh shrimp, mussels, and clams in one stunning pan. The socarrat, the golden crispy rice crust on the bottom, is the hallmark of an authentic paella done right.','A vibrant saffron-kissed rice dish loaded with fresh seafood and cooked in one pan for a true Spanish feast.','Spanish','Medium',20,40,60,4,520,38,58,12,3,'[{"amount":2,"unit":"cups","item":"short grain bomba rice","group":"Base"},{"amount":0.5,"unit":"tsp","item":"saffron threads","group":"Base"},{"amount":4,"unit":"cups","item":"seafood stock","group":"Base"},{"amount":300,"unit":"g","item":"large shrimp peeled and deveined","group":"Seafood"},{"amount":300,"unit":"g","item":"fresh mussels scrubbed and debearded","group":"Seafood"},{"amount":200,"unit":"g","item":"clams scrubbed","group":"Seafood"},{"amount":1,"unit":"cup","item":"crushed tomatoes","group":"Sauce"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"Aromatics"}]','[{"title":"Bloom the Saffron","text":"Warm the seafood stock in a saucepan over low heat. Add the saffron threads to the warm stock and let them steep for 10 minutes until the stock turns a deep golden color. This releases the full flavor and color of the saffron into the broth.","timer":600},{"title":"Build the Sofrito","text":"Heat 3 tablespoons of olive oil in a large paella pan or wide skillet over medium heat. Add the minced garlic and cook for 1 minute until fragrant. Stir in the crushed tomatoes and cook for 5 to 7 minutes, stirring occasionally, until the mixture darkens and thickens into a rich sofrito base.","timer":420},{"title":"Toast the Rice","text":"Add the bomba rice directly to the sofrito and stir to coat every grain evenly with the tomato mixture. Cook for 2 minutes, toasting the rice slightly. Pour in the saffron-infused stock, spread the rice evenly across the pan, and do not stir again from this point forward.","timer":120},{"title":"Add the Seafood","text":"Once the stock begins to simmer, nestle the shrimp, mussels, and clams into the rice in a decorative pattern. Cook over medium heat for 18 to 20 minutes without stirring. The mussels and clams will open as they cook and the rice will absorb all the liquid.","timer":1200},{"title":"Form the Socarrat","text":"Increase the heat to medium-high for the last 2 minutes of cooking to create the socarrat, the prized crispy bottom layer of rice. Listen for a faint crackling sound and check the bottom with a spoon. Remove from heat, cover with foil, and rest for 5 minutes before serving with lemon wedges.","timer":300}]','[{"original":"bomba rice","swap":"arborio rice works as a close substitute though it absorbs slightly less liquid"},{"original":"seafood stock","swap":"chicken stock combined with a splash of clam juice delivers great depth"},{"original":"fresh mussels","swap":"frozen mussel meat can be used and added in the last 5 minutes of cooking"}]','["Stirring the rice after adding the stock which destroys the socarrat and makes the texture gummy","Using too much liquid which prevents the crispy bottom from forming properly","Cooking on too low a heat which steams rather than fries the bottom layer of rice"]','["paella","seafood","Spanish","one-pan","saffron","rice","dinner party","mussels","shrimp","clams"]','["Gluten-Free","Dairy-Free","Pescatarian"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Thai Pad See Ew','thai-pad-see-ew','Pad See Ew is a beloved Thai street food dish featuring wide rice noodles stir-fried with egg, Chinese broccoli, and a savory-sweet soy sauce blend. The high-heat wok technique creates a beautiful char on the noodles that gives this dish its signature smoky depth.','Silky wide rice noodles stir-fried with egg and Chinese broccoli in a rich sweet soy sauce with irresistible wok char.','Thai','Easy',15,15,30,2,480,24,68,11,4,'[{"amount":250,"unit":"g","item":"fresh wide rice noodles","group":"Base"},{"amount":200,"unit":"g","item":"chicken breast thinly sliced","group":"Protein"},{"amount":2,"unit":"large","item":"eggs","group":"Protein"},{"amount":3,"unit":"cups","item":"Chinese broccoli gai lan cut into pieces","group":"Vegetables"},{"amount":3,"unit":"tbsp","item":"dark soy sauce","group":"Sauce"},{"amount":2,"unit":"tbsp","item":"oyster sauce","group":"Sauce"},{"amount":1,"unit":"tbsp","item":"white sugar","group":"Sauce"},{"amount":3,"unit":"cloves","item":"garlic minced","group":"Aromatics"}]','[{"title":"Prepare the Sauce and Noodles","text":"Whisk together the dark soy sauce, oyster sauce, and white sugar in a small bowl until the sugar dissolves completely. Separate the wide rice noodles gently with your hands to prevent them from clumping during cooking. If using refrigerated noodles, let them come to room temperature for 10 minutes first.","timer":0},{"title":"Sear the Chicken","text":"Heat 2 tablespoons of neutral oil in a wok or large skillet over the highest heat possible until smoking. Add the sliced chicken in a single layer and do not move it for 90 seconds to build a good sear. Flip and cook for another 60 seconds until cooked through, then push to the side of the wok.","timer":150},{"title":"Cook the Aromatics and Eggs","text":"Add the minced garlic to the empty side of the wok and stir-fry for 30 seconds until golden and fragrant. Crack both eggs into the wok and scramble them quickly, cooking for about 60 seconds until just set but still slightly soft. Mix the egg and chicken together.","timer":90},{"title":"Add Noodles and Sauce","text":"Add the separated rice noodles to the wok and pour the sauce mixture over everything. Toss and fold the noodles continuously for 2 minutes, allowing them to coat evenly in the dark sauce. Press the noodles against the hot surface of the wok in intervals to develop char and do not over-stir.","timer":120},{"title":"Finish with Greens and Serve","text":"Add the Chinese broccoli to the wok and stir-fry for 2 minutes until the stems are tender and the leaves are wilted. Taste and adjust seasoning with additional soy sauce or a pinch of sugar if needed. Serve immediately with white pepper, chili flakes, and fish sauce on the side.","timer":120}]','[{"original":"Chinese broccoli","swap":"regular broccoli florets or broccolini are excellent substitutes with similar texture"},{"original":"fresh wide rice noodles","swap":"dried rice noodles soaked in warm water for 30 minutes can replace fresh noodles"},{"original":"chicken breast","swap":"firm tofu pressed and cubed makes a great vegetarian alternative with the same cooking method"}]','["Cooking on too low a heat which steams the noodles instead of creating the essential smoky wok char","Overcrowding the wok which drops the temperature and results in soggy noodles","Stirring the noodles constantly which prevents the caramelized char from forming on the noodle surface"]','["Thai","noodles","stir-fry","pad see ew","wok","street food","quick","weeknight","Asian","soy sauce"]','["Dairy-Free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Southern Fried Chicken','southern-fried-chicken','This Southern Fried Chicken is brined in seasoned buttermilk overnight for incredibly juicy and flavorful meat beneath a shatteringly crispy seasoned crust. Every bite delivers the perfect balance of crunchy coating, aromatic spices, and tender chicken that the South is famous for.','Buttermilk-brined chicken fried to golden perfection with a thick and crunchy spiced flour crust.','American','Medium',20,30,50,4,610,42,36,32,2,'[{"amount":1.5,"unit":"kg","item":"bone-in skin-on chicken pieces","group":"Protein"},{"amount":2,"unit":"cups","item":"buttermilk","group":"Brine"},{"amount":2,"unit":"cups","item":"all-purpose flour","group":"Coating"},{"amount":2,"unit":"tsp","item":"smoked paprika","group":"Seasoning"},{"amount":1.5,"unit":"tsp","item":"garlic powder","group":"Seasoning"},{"amount":1,"unit":"tsp","item":"cayenne pepper","group":"Seasoning"},{"amount":2,"unit":"tsp","item":"fine sea salt","group":"Seasoning"},{"amount":4,"unit":"cups","item":"vegetable oil for frying","group":"Cooking"}]','[{"title":"Brine the Chicken","text":"Combine the buttermilk with 1 teaspoon of salt, half the garlic powder, and half the cayenne in a large bowl. Submerge all the chicken pieces completely in the buttermilk brine, cover tightly, and refrigerate for a minimum of 4 hours or ideally overnight. This step is non-negotiable for juicy and flavorful meat.","timer":0},{"title":"Prepare the Seasoned Flour","text":"In a large shallow dish, whisk together the all-purpose flour, smoked paprika, remaining garlic powder, remaining cayenne, and remaining salt until evenly combined. For extra texture, add 2 tablespoons of the leftover buttermilk brine directly into the flour and work it in with your fingers to create small clumps.","timer":0},{"title":"Dredge the Chicken","text":"Remove each piece of chicken from the buttermilk brine, letting the excess drip off for a few seconds. Press each piece firmly into the seasoned flour, turning and pressing multiple times to build up a thick and even coating. Place the dredged pieces on a wire rack and rest for 10 minutes so the coating adheres properly.","timer":600},{"title":"Fry the Chicken","text":"Heat the vegetable oil in a large cast iron skillet or Dutch oven to 325 degrees Fahrenheit. Carefully lower the chicken pieces in skin-side down, working in batches to avoid crowding. Fry thighs and drumsticks for 13 to 15 minutes per side and breasts for 10 to 12 minutes per side until deep golden brown and cooked through to 165 degrees internally.","timer":900},{"title":"Drain and Rest","text":"Transfer the finished chicken pieces to a clean wire rack set over a baking sheet rather than paper towels, which trap steam and soften the crust. Let the chicken rest for at least 5 minutes before serving so the juices redistribute throughout the meat. Serve with hot sauce, biscuits, and honey on the side.","timer":300}]','[{"original":"buttermilk","swap":"whole milk mixed with 1 tablespoon of white vinegar per cup creates an effective buttermilk substitute"},{"original":"smoked paprika","swap":"regular paprika combined with a small pinch of cumin delivers a similar warm flavor"},{"original":"vegetable oil","swap":"peanut oil is the traditional Southern choice and has a higher smoke point for cleaner frying"}]','["Skipping the resting period after dredging which causes the coating to slide off during frying","Frying at too high a temperature which burns the crust before the inside cooks through","Placing fried chicken on paper towels which traps steam and destroys the crispy crust you worked hard to create"]','["fried chicken","Southern","comfort food","crispy","buttermilk","American","cast iron","classic","dinner","weekend"]','["Dairy-Free option"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Chicken Marsala','chicken-marsala','Chicken Marsala is a classic Italian-American dish featuring tender pan-seared chicken breasts smothered in a rich and savory Marsala wine sauce with earthy mushrooms. This restaurant-quality meal comes together in under 45 minutes and is perfect for a special weeknight dinner or an impressive dinner party dish.','Pan-seared chicken in a rich Marsala wine and mushroom sauce ready in 45 minutes.','Italian-American','Medium',10,30,40,4,420,38,14,22,1,'[{"amount":4,"unit":"pieces","item":"boneless skinless chicken breasts pounded thin","group":"Chicken"},{"amount":0.5,"unit":"cup","item":"all-purpose flour for dredging","group":"Chicken"},{"amount":2,"unit":"tablespoons","item":"olive oil","group":"Cooking"},{"amount":3,"unit":"tablespoons","item":"unsalted butter","group":"Cooking"},{"amount":8,"unit":"ounces","item":"cremini mushrooms sliced","group":"Sauce"},{"amount":0.75,"unit":"cup","item":"dry Marsala wine","group":"Sauce"},{"amount":0.5,"unit":"cup","item":"chicken broth","group":"Sauce"},{"amount":2,"unit":"tablespoons","item":"fresh flat-leaf parsley chopped","group":"Garnish"}]','[{"title":"Pound and Dredge the Chicken","text":"Place chicken breasts between two sheets of plastic wrap and pound to an even 1/4 inch thickness. Season both sides generously with salt and pepper. Dredge each piece in flour, shaking off any excess so only a light coating remains.","timer":0},{"title":"Sear the Chicken","text":"Heat olive oil and 1 tablespoon of butter in a large skillet over medium-high heat until shimmering. Add the chicken pieces in a single layer and sear for 4 to 5 minutes per side until golden brown and cooked through. Transfer to a plate and cover loosely with foil.","timer":600},{"title":"Saute the Mushrooms","text":"In the same skillet, add another tablespoon of butter and the sliced cremini mushrooms. Cook over medium heat for 5 to 6 minutes, stirring occasionally, until the mushrooms are golden and have released their moisture. Season lightly with salt and pepper.","timer":360},{"title":"Build the Marsala Sauce","text":"Pour the Marsala wine into the skillet and use a wooden spoon to scrape up any browned bits from the bottom. Add the chicken broth and bring the mixture to a gentle boil. Reduce heat and simmer for 8 to 10 minutes until the sauce has reduced by about half and coats the back of a spoon.","timer":600},{"title":"Finish and Serve","text":"Swirl in the remaining tablespoon of butter to give the sauce a silky finish. Return the chicken and any resting juices to the skillet and spoon the sauce generously over the top. Cook for 2 more minutes to heat through, then garnish with fresh parsley and serve immediately.","timer":120}]','[{"original":"dry Marsala wine","swap":"dry sherry or Madeira wine for a similar depth of flavor"},{"original":"cremini mushrooms","swap":"baby bella or shiitake mushrooms for a more earthy taste"},{"original":"chicken breasts","swap":"chicken cutlets to skip the pounding step and save time"}]','["Skipping the pounding step which leads to uneven cooking and tough chicken","Using sweet Marsala wine instead of dry which makes the sauce overly sugary","Crowding the pan when searing which causes the chicken to steam rather than brown properly"]','["chicken marsala","italian chicken","marsala wine","mushroom sauce","date night dinner","30 minute meals","pan sauce","skillet chicken"]','["Gluten-Free Adaptable"]','Dinner','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Air Fryer Chicken Tenders','air-fryer-chicken-tenders','These Air Fryer Chicken Tenders are incredibly crispy on the outside and juicy on the inside without a drop of deep-frying oil. A seasoned breadcrumb coating delivers that satisfying crunch that everyone loves, and they are ready in just 20 minutes making them perfect for busy weeknights.','Ultra-crispy breaded chicken tenders made in the air fryer in just 20 minutes.','American','Easy',10,12,22,4,310,34,22,9,1,'[{"amount":1.5,"unit":"pounds","item":"chicken tenders or chicken breasts cut into strips","group":"Chicken"},{"amount":1,"unit":"cup","item":"panko breadcrumbs","group":"Coating"},{"amount":0.5,"unit":"cup","item":"all-purpose flour","group":"Coating"},{"amount":2,"unit":"large","item":"eggs beaten","group":"Coating"},{"amount":1,"unit":"teaspoon","item":"garlic powder","group":"Seasoning"},{"amount":1,"unit":"teaspoon","item":"smoked paprika","group":"Seasoning"},{"amount":0.5,"unit":"teaspoon","item":"onion powder","group":"Seasoning"},{"amount":1,"unit":"tablespoon","item":"olive oil spray","group":"Cooking"}]','[{"title":"Prepare the Breading Station","text":"Set up three shallow bowls in a row. Fill the first with flour seasoned with salt, pepper, garlic powder, onion powder, and smoked paprika. Fill the second with the beaten eggs. Fill the third with panko breadcrumbs. This assembly line approach ensures each tender gets an even and thorough coating.","timer":0},{"title":"Bread the Chicken Tenders","text":"Pat the chicken tenders dry with paper towels. Working one at a time, dredge each tender in the seasoned flour and shake off the excess. Dip it into the egg, letting any drips fall off, then press it firmly into the panko breadcrumbs coating all sides evenly. Place coated tenders on a clean plate.","timer":0},{"title":"Preheat and Arrange in Air Fryer","text":"Preheat your air fryer to 400 degrees Fahrenheit for 3 minutes. Lightly spray the air fryer basket with olive oil spray. Arrange the breaded chicken tenders in a single layer making sure they do not overlap. Spray the tops of the tenders lightly with olive oil spray to promote browning.","timer":180},{"title":"Air Fry the Tenders","text":"Cook the tenders at 400 degrees Fahrenheit for 10 to 12 minutes, flipping them halfway through at the 5 or 6 minute mark. Spray the freshly flipped side lightly with oil before continuing to cook. The tenders are done when the coating is deep golden brown and the internal temperature reaches 165 degrees Fahrenheit.","timer":720},{"title":"Rest and Serve","text":"Remove the tenders from the air fryer and let them rest for 2 minutes before serving. This brief rest allows the juices to redistribute and keeps the inside moist. Serve immediately with your favorite dipping sauces such as honey mustard, ranch, or barbecue sauce.","timer":120}]','[{"original":"panko breadcrumbs","swap":"crushed cornflakes for an extra crunchy and slightly sweet coating"},{"original":"all-purpose flour","swap":"almond flour for a gluten-free and lower-carb alternative"},{"original":"smoked paprika","swap":"cayenne pepper for a spicy kick in the seasoning blend"}]','["Not patting the chicken dry before breading which causes the coating to slip off during cooking","Overcrowding the air fryer basket which traps steam and results in soggy rather than crispy tenders","Skipping the oil spray on the breadcrumbs which leads to a pale and dry coating instead of a golden crust"]','["air fryer chicken","chicken tenders","crispy chicken","kid friendly","quick dinner","healthy fried chicken","weeknight meals","finger food"]','["Dairy-Free","Gluten-Free Adaptable"]','Dinner','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Creamy Mushroom Chicken Thighs','creamy-mushroom-chicken-thighs','Creamy Mushroom Chicken Thighs feature golden seared bone-in chicken thighs bathed in a luscious garlic and herb cream sauce loaded with tender mushrooms. This hearty one-pan meal is pure comfort food that pairs beautifully with mashed potatoes, pasta, or crusty bread to soak up every drop of that incredible sauce.','Golden seared chicken thighs simmered in a garlic herb cream sauce with mushrooms.','American','Medium',10,35,45,4,510,36,8,37,1,'[{"amount":4,"unit":"pieces","item":"bone-in skin-on chicken thighs","group":"Chicken"},{"amount":10,"unit":"ounces","item":"baby bella mushrooms sliced","group":"Sauce"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"Sauce"},{"amount":1,"unit":"cup","item":"heavy cream","group":"Sauce"},{"amount":0.5,"unit":"cup","item":"chicken broth","group":"Sauce"},{"amount":1,"unit":"teaspoon","item":"dried thyme","group":"Seasoning"},{"amount":2,"unit":"tablespoons","item":"olive oil","group":"Cooking"},{"amount":2,"unit":"tablespoons","item":"freshly grated Parmesan cheese","group":"Garnish"}]','[{"title":"Season and Sear the Chicken Thighs","text":"Pat the chicken thighs completely dry with paper towels and season both sides generously with salt, pepper, and dried thyme. Heat olive oil in a large oven-safe skillet over medium-high heat. Place the thighs skin-side down and sear for 6 to 8 minutes without moving them until the skin is deeply golden and crispy. Flip and sear the other side for 4 minutes, then transfer to a plate.","timer":720},{"title":"Saute the Mushrooms","text":"Reduce heat to medium and add the sliced mushrooms to the same skillet with all the rendered chicken fat. Cook for 5 to 6 minutes, stirring occasionally, until the mushrooms are deeply browned and their liquid has evaporated completely. Do not rush this step as properly browned mushrooms add tremendous depth to the sauce.","timer":360},{"title":"Build the Cream Sauce","text":"Add the minced garlic to the mushrooms and cook for 1 minute until fragrant, stirring constantly so the garlic does not burn. Pour in the chicken broth and scrape up any browned bits from the bottom of the pan. Let the broth reduce by half for about 2 minutes, then pour in the heavy cream and stir everything together well.","timer":180},{"title":"Simmer with Chicken","text":"Return the seared chicken thighs to the skillet, nestling them skin-side up into the cream sauce so the crispy skin stays above the liquid. Bring the sauce to a gentle simmer, then reduce heat to medium-low. Cook uncovered for 15 to 18 minutes until the chicken is cooked through to an internal temperature of 165 degrees Fahrenheit and the sauce has thickened nicely.","timer":1080},{"title":"Finish and Serve","text":"Taste the sauce and adjust seasoning with additional salt and pepper as needed. Sprinkle the freshly grated Parmesan cheese over the top of the chicken and sauce. Let it melt for 1 minute, then garnish with fresh thyme or parsley if desired. Serve directly from the pan with your choice of sides to soak up the creamy sauce.","timer":60}]','[{"original":"heavy cream","swap":"full-fat coconut milk for a dairy-free version with a subtle sweetness"},{"original":"baby bella mushrooms","swap":"a mix of shiitake and oyster mushrooms for a more complex earthy flavor"},{"original":"bone-in skin-on chicken thighs","swap":"boneless skinless thighs for quicker cooking though you will lose some of the rendered fat flavor"}]','["Not drying the chicken skin before searing which causes steaming instead of crisping and results in rubbery skin","Cooking the mushrooms over low heat which causes them to steam in their own liquid instead of browning properly","Allowing the cream sauce to boil vigorously which can cause it to break and become greasy rather than smooth"]','["creamy chicken","mushroom chicken","chicken thighs","one pan meal","comfort food","cream sauce","weeknight dinner","skillet chicken"]','["Gluten-Free","Low-Carb"]','Dinner','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Beef Stroganoff','beef-stroganoff','This classic Russian dish features tender strips of beef simmered in a rich and creamy mushroom sauce served over egg noodles. It is the ultimate comfort food that comes together in under an hour for a satisfying weeknight dinner.','Tender beef and mushrooms in a silky sour cream sauce served over buttery egg noodles.','Russian','Medium',15,30,45,4,620,38,42,32,3,'[{"amount":1.5,"unit":"lb","item":"beef sirloin thinly sliced","group":"Protein"},{"amount":8,"unit":"oz","item":"cremini mushrooms sliced","group":"Vegetables"},{"amount":1,"unit":"medium","item":"yellow onion diced","group":"Vegetables"},{"amount":3,"unit":"cloves","item":"garlic minced","group":"Aromatics"},{"amount":1,"unit":"cup","item":"sour cream","group":"Sauce"},{"amount":2,"unit":"cups","item":"beef broth","group":"Sauce"},{"amount":12,"unit":"oz","item":"egg noodles","group":"Base"},{"amount":2,"unit":"tbsp","item":"all purpose flour","group":"Thickener"}]','[{"title":"Cook the Noodles","text":"Bring a large pot of salted water to a boil and cook egg noodles according to package directions until al dente. Drain and set aside tossing with a little butter to prevent sticking.","timer":600},{"title":"Sear the Beef","text":"Season beef strips with salt and pepper. Heat a large skillet over high heat with oil and sear the beef in a single layer for 1 to 2 minutes per side until browned. Work in batches to avoid steaming. Remove beef and set aside.","timer":300},{"title":"Saute Vegetables","text":"In the same skillet reduce heat to medium and add onions and mushrooms. Cook for 6 to 8 minutes until softened and golden brown. Add garlic and cook for 1 more minute until fragrant.","timer":480},{"title":"Build the Sauce","text":"Sprinkle flour over the vegetables and stir to coat. Pour in beef broth and bring to a simmer stirring constantly until the sauce thickens about 4 to 5 minutes. Reduce heat to low and stir in sour cream until smooth and creamy.","timer":300},{"title":"Combine and Serve","text":"Return the seared beef to the skillet and stir to coat in the sauce. Simmer gently for 3 to 4 minutes until beef is cooked through. Serve immediately over egg noodles garnished with fresh parsley.","timer":240}]','[{"original":"sour cream","swap":"full fat Greek yogurt for a lighter option with similar tanginess"},{"original":"beef sirloin","swap":"beef tenderloin or ribeye for an even more tender result"},{"original":"egg noodles","swap":"mashed potatoes or white rice for a gluten friendly base"}]','["Boiling the sour cream which causes it to curdle so always add it off heat or on very low temperature","Overcrowding the pan when searing beef which causes it to steam instead of developing a proper brown crust","Slicing the beef too thick which results in chewy and tough pieces instead of tender bites"]','["comfort food","beef","mushrooms","creamy","weeknight dinner","pasta","classic","one pan"]','["nut free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Swedish Meatballs with Gravy','swedish-meatballs-with-gravy','These tender and juicy Swedish meatballs are made with a blend of beef and pork and smothered in a velvety cream gravy that is deeply savory and satisfying. Inspired by the beloved Scandinavian classic they are perfect served over mashed potatoes or egg noodles.','Juicy beef and pork meatballs bathed in a rich and creamy Swedish style brown gravy.','Swedish','Medium',20,30,50,4,580,34,22,38,1,'[{"amount":0.75,"unit":"lb","item":"ground beef","group":"Protein"},{"amount":0.75,"unit":"lb","item":"ground pork","group":"Protein"},{"amount":0.5,"unit":"cup","item":"breadcrumbs","group":"Binder"},{"amount":1,"unit":"large","item":"egg","group":"Binder"},{"amount":2,"unit":"cups","item":"beef broth","group":"Gravy"},{"amount":1,"unit":"cup","item":"heavy cream","group":"Gravy"},{"amount":0.5,"unit":"tsp","item":"ground allspice","group":"Seasoning"},{"amount":2,"unit":"tbsp","item":"unsalted butter","group":"Gravy"}]','[{"title":"Mix the Meatballs","text":"Combine ground beef ground pork breadcrumbs egg allspice salt and pepper in a large bowl. Mix gently with your hands until just combined being careful not to overwork the meat. Roll into balls about 1.5 inches in diameter.","timer":600},{"title":"Brown the Meatballs","text":"Melt butter in a large skillet over medium high heat. Working in batches brown the meatballs on all sides for about 4 to 5 minutes total. They do not need to be fully cooked through at this stage. Remove and set aside.","timer":420},{"title":"Make the Gravy Base","text":"In the same skillet melt an additional tablespoon of butter and whisk in 2 tablespoons of flour until a smooth paste forms. Cook for 1 to 2 minutes until lightly golden then gradually whisk in beef broth until smooth and lump free.","timer":180},{"title":"Finish the Gravy","text":"Pour in heavy cream and bring the gravy to a gentle simmer stirring frequently. Season with salt pepper and a pinch of allspice. Cook for 4 to 5 minutes until the gravy thickens enough to coat the back of a spoon.","timer":300},{"title":"Simmer and Serve","text":"Return the browned meatballs to the skillet and nestle them into the gravy. Cover and simmer on low heat for 10 to 12 minutes until the meatballs are fully cooked through. Serve over mashed potatoes or egg noodles with a sprinkle of fresh parsley.","timer":720}]','[{"original":"ground pork","swap":"all ground beef for a leaner version though the texture will be slightly firmer"},{"original":"heavy cream","swap":"whole milk or half and half for a lighter gravy with less richness"},{"original":"breadcrumbs","swap":"crushed crackers or rolled oats for a slightly different but effective binding texture"}]','["Overmixing the meat mixture which develops too much protein and results in dense and rubbery meatballs","Skipping the browning step and just simmering meatballs directly in the gravy which sacrifices deep flavor development","Adding cream to a sauce that is too hot causing it to break and become greasy instead of silky"]','["swedish","meatballs","comfort food","gravy","creamy","pork","beef","family dinner","classic"]','["nut free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Smash Burgers','smash-burgers','Smash burgers are thin crispy edged patties made by pressing ground beef balls directly onto a screaming hot griddle creating incredible caramelized crust and juicy centers. Stacked with melty American cheese and classic toppings on a toasted brioche bun they are the ultimate fast food experience made at home.','Thin and crispy edged beef patties with melty cheese on a toasted brioche bun.','American','Easy',10,15,25,4,710,42,38,44,2,'[{"amount":2,"unit":"lb","item":"80 percent lean ground beef","group":"Protein"},{"amount":8,"unit":"slices","item":"American cheese","group":"Dairy"},{"amount":4,"unit":"unit","item":"brioche burger buns","group":"Base"},{"amount":0.5,"unit":"cup","item":"mayonnaise","group":"Sauce"},{"amount":1,"unit":"tbsp","item":"yellow mustard","group":"Sauce"},{"amount":1,"unit":"medium","item":"white onion thinly sliced","group":"Vegetables"},{"amount":4,"unit":"leaves","item":"iceberg lettuce","group":"Vegetables"},{"amount":2,"unit":"medium","item":"tomatoes sliced","group":"Vegetables"}]','[{"title":"Prepare the Beef Balls","text":"Divide ground beef into 8 equal portions of about 4 ounces each and roll them loosely into balls. Do not pack them tightly as a loose ball smashes more easily. Season the tops generously with salt and pepper just before cooking.","timer":300},{"title":"Heat the Griddle","text":"Place a cast iron skillet or flat griddle over high heat and let it preheat for at least 3 to 4 minutes until it is smoking hot. A screaming hot surface is essential for achieving the signature crispy crust that defines a smash burger.","timer":240},{"title":"Smash the Patties","text":"Place two beef balls on the griddle at a time. Immediately press each ball down firmly with a heavy spatula or burger press for 10 seconds until the patty is very thin about a quarter inch thick. Cook undisturbed for 2 to 3 minutes until the edges are deeply browned and crispy.","timer":180},{"title":"Add Cheese and Flip","text":"Flip each patty quickly and immediately place one slice of American cheese on top. Let the cheese melt for about 60 seconds. For a double smash burger stack two patties together before removing from the griddle. Toast your buns cut side down on the griddle for 30 seconds.","timer":90},{"title":"Build and Serve","text":"Spread a mixture of mayonnaise and mustard on both bun halves. Layer lettuce tomato and onion on the bottom bun then add the cheesy patties. Serve immediately as smash burgers are best enjoyed fresh off the griddle while still hot and crispy.","timer":120}]','[{"original":"American cheese","swap":"cheddar or pepper jack cheese for a more bold and sharp flavor profile"},{"original":"brioche buns","swap":"potato rolls or classic sesame seed buns for a more traditional burger experience"},{"original":"mayonnaise","swap":"special sauce made with mayo ketchup and relish for extra classic diner flavor"}]','["Using lean ground beef which does not have enough fat to create the juicy and flavorful crust that smash burgers require","Smashing the patty too late after it has already started to set which prevents it from spreading thin and forming crispy edges","Pressing down repeatedly during cooking instead of just one firm initial smash which squeezes out the juices and dries out the burger"]','["burger","american","beef","griddle","cheese","fast food","weeknight","easy","crispy"]','["nut free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Cast Iron Ribeye Steak','cast-iron-ribeye-steak','A perfectly seared ribeye steak cooked in a screaming hot cast iron skillet with butter and fresh herbs. This method creates a beautiful crust on the outside while keeping the inside juicy and tender.','A restaurant-quality ribeye steak seared to perfection in a cast iron skillet with herb butter.','American','Medium',10,15,25,2,680,52,1,51,0,'[{"amount":2,"unit":"pieces","item":"ribeye steaks 1 inch thick","group":"Main"},{"amount":2,"unit":"tablespoons","item":"kosher salt","group":"Seasoning"},{"amount":1,"unit":"tablespoon","item":"black pepper coarsely ground","group":"Seasoning"},{"amount":2,"unit":"tablespoons","item":"vegetable oil","group":"Cooking"},{"amount":3,"unit":"tablespoons","item":"unsalted butter","group":"Cooking"},{"amount":4,"unit":"cloves","item":"garlic smashed","group":"Aromatics"},{"amount":3,"unit":"sprigs","item":"fresh thyme","group":"Aromatics"},{"amount":2,"unit":"sprigs","item":"fresh rosemary","group":"Aromatics"}]','[{"title":"Season and Rest the Steaks","text":"Pat both ribeye steaks completely dry with paper towels. Season generously on all sides with kosher salt and coarsely ground black pepper, pressing the seasoning firmly into the meat. Let the steaks rest at room temperature for at least 30 minutes before cooking to ensure even cooking throughout.","timer":1800},{"title":"Preheat the Cast Iron Skillet","text":"Place your cast iron skillet over high heat and allow it to preheat for 4 to 5 minutes until it is extremely hot and just beginning to smoke. A properly preheated skillet is the most important step for achieving a great crust on the steak. Add the vegetable oil and swirl to coat the surface.","timer":300},{"title":"Sear the First Side","text":"Carefully place the steaks in the hot skillet and do not move them for 3 to 4 minutes. You should hear a loud sizzle immediately upon contact. Allow the crust to form completely before flipping. The steak should release naturally from the pan when the crust is properly formed.","timer":240},{"title":"Flip and Baste with Butter","text":"Flip the steaks and immediately add the butter, smashed garlic cloves, thyme, and rosemary to the pan. As the butter melts and begins to foam, tilt the pan slightly and use a spoon to continuously baste the steaks with the herb butter. Cook for another 3 to 4 minutes for medium rare, basting constantly throughout.","timer":240},{"title":"Rest and Serve","text":"Transfer the steaks to a cutting board and let them rest for at least 5 minutes before cutting. This allows the juices to redistribute throughout the meat for a more tender and flavorful result. Spoon any remaining herb butter from the pan over the steaks before serving.","timer":300}]','[{"original":"ribeye steak","swap":"New York strip steak"},{"original":"fresh thyme and rosemary","swap":"dried herbs mixed with softened butter"},{"original":"vegetable oil","swap":"avocado oil or grapeseed oil"}]','["Not patting the steaks dry before seasoning which prevents a proper crust from forming","Moving the steak around in the pan before the crust has fully developed","Skipping the resting period and cutting into the steak immediately which causes all the juices to run out"]','["steak","cast iron","beef","dinner","high protein","date night","quick dinner"]','["Gluten Free","Low Carb","Keto"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Mongolian Beef','mongolian-beef','Tender strips of flank steak coated in a savory and slightly sweet soy ginger sauce with crispy fried onions and green onions. This popular Chinese American dish comes together quickly in a wok and tastes better than any takeout version.','Crispy tender beef strips tossed in a rich savory soy ginger sauce that rivals your favorite takeout restaurant.','Chinese American','Medium',15,20,35,4,420,34,28,18,2,'[{"amount":1.5,"unit":"pounds","item":"flank steak thinly sliced against the grain","group":"Main"},{"amount":0.5,"unit":"cup","item":"cornstarch","group":"Coating"},{"amount":0.5,"unit":"cup","item":"soy sauce low sodium","group":"Sauce"},{"amount":0.33,"unit":"cup","item":"brown sugar packed","group":"Sauce"},{"amount":1,"unit":"tablespoon","item":"fresh ginger minced","group":"Sauce"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"Sauce"},{"amount":4,"unit":"stalks","item":"green onions cut into 2 inch pieces","group":"Garnish"},{"amount":0.5,"unit":"cup","item":"vegetable oil for frying","group":"Cooking"}]','[{"title":"Prepare and Coat the Beef","text":"Slice the flank steak as thinly as possible against the grain, ideally about a quarter inch thick. Place the sliced beef in a large bowl and toss with the cornstarch until every piece is evenly coated. Shake off any excess cornstarch and spread the pieces out on a plate. The cornstarch coating is what gives the beef its signature crispy exterior.","timer":900},{"title":"Make the Mongolian Sauce","text":"In a small bowl or measuring cup, whisk together the soy sauce, brown sugar, minced ginger, and minced garlic until the sugar is fully dissolved. Set the sauce aside while you cook the beef. You can also add a quarter cup of water to the sauce if you prefer a thinner consistency.","timer":300},{"title":"Fry the Beef in Batches","text":"Heat the vegetable oil in a large wok or heavy pan over high heat until the oil reaches about 350 degrees Fahrenheit. Working in batches to avoid crowding, fry the cornstarch coated beef pieces for 2 minutes per batch until they are crispy and golden brown. Remove with a slotted spoon and drain on paper towels.","timer":480},{"title":"Build the Sauce and Combine","text":"Pour off most of the oil from the wok, leaving about 1 tablespoon behind. Return the wok to high heat and pour in the prepared sauce. Let it bubble and reduce for about 2 minutes until it thickens slightly and becomes glossy. Add all of the fried beef back into the wok and toss quickly to coat every piece evenly in the sauce.","timer":120},{"title":"Add Green Onions and Serve","text":"Add the green onion pieces to the wok and toss everything together for about 30 seconds just until the onions are slightly wilted but still have some crunch. Serve immediately over steamed white rice. The dish is best enjoyed fresh as the beef coating may soften as it sits.","timer":30}]','[{"original":"flank steak","swap":"skirt steak or sirloin thinly sliced"},{"original":"brown sugar","swap":"honey or coconut sugar"},{"original":"soy sauce","swap":"tamari for a gluten free version"}]','["Slicing the beef with the grain instead of against it which results in chewy tough pieces","Overcrowding the pan when frying the beef which causes steaming instead of crisping","Cooking the green onions too long and losing their fresh flavor and color"]','["beef","Chinese takeout","wok","quick dinner","savory","weeknight","stir fry"]','["Dairy Free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Philly Cheesesteak Sandwiches','philly-cheesesteak-sandwiches','Thinly shaved ribeye steak cooked with caramelized onions and green peppers then piled high on a toasted hoagie roll with melted provolone cheese. This iconic Philadelphia sandwich delivers a perfect combination of savory meat, sweet vegetables, and gooey melted cheese in every single bite.','An authentic Philly cheesesteak loaded with shaved ribeye, sauteed peppers and onions, and melted provolone on a toasted hoagie roll.','American','Easy',15,20,35,4,720,45,52,38,3,'[{"amount":2,"unit":"pounds","item":"ribeye steak shaved or very thinly sliced","group":"Main"},{"amount":4,"unit":"pieces","item":"hoagie rolls split lengthwise","group":"Bread"},{"amount":8,"unit":"slices","item":"provolone cheese","group":"Cheese"},{"amount":2,"unit":"medium","item":"yellow onions thinly sliced","group":"Vegetables"},{"amount":2,"unit":"medium","item":"green bell peppers thinly sliced","group":"Vegetables"},{"amount":3,"unit":"tablespoons","item":"vegetable oil divided","group":"Cooking"},{"amount":1,"unit":"teaspoon","item":"kosher salt","group":"Seasoning"},{"amount":1,"unit":"teaspoon","item":"black pepper freshly ground","group":"Seasoning"}]','[{"title":"Caramelize the Onions and Peppers","text":"Heat 2 tablespoons of vegetable oil in a large skillet or flat griddle over medium high heat. Add the sliced onions and green bell peppers with a pinch of salt and cook, stirring occasionally, for about 10 minutes until the onions are soft and golden brown and the peppers are tender. Remove the vegetables from the pan and set aside.","timer":600},{"title":"Cook the Shaved Ribeye","text":"Increase the heat to high and add the remaining tablespoon of oil to the same pan. Add the shaved ribeye steak in a single layer and season with salt and black pepper. Cook without stirring for about 2 minutes to develop some color, then use a spatula to chop and break up the meat as it cooks for another 2 minutes until fully cooked through and slightly crispy at the edges.","timer":240},{"title":"Combine Beef and Vegetables","text":"Return the cooked onions and peppers to the pan with the beef and toss everything together until well combined. Divide the mixture into 4 equal portions in the pan and top each portion with 2 slices of provolone cheese. Cover the pan with a lid or aluminum foil for about 1 minute until the cheese is fully melted and gooey over each portion.","timer":60},{"title":"Toast the Hoagie Rolls","text":"While the cheese melts, place the hoagie rolls cut side down in a separate dry skillet or under the broiler for about 2 minutes until lightly golden and toasted. Toasting the rolls is essential because it prevents them from becoming soggy once the juicy beef mixture is added. Watch them carefully as they can burn quickly under the broiler.","timer":120},{"title":"Assemble and Serve","text":"Using a spatula, scoop each cheesy beef and vegetable portion into a toasted hoagie roll. Serve the sandwiches immediately while everything is hot and the cheese is still melted. If desired, you can add condiments like hot sauce, mayo, or banana peppers to customize your sandwich to your preference.","timer":60}]','[{"original":"ribeye steak","swap":"top round steak or sirloin shaved thin"},{"original":"provolone cheese","swap":"American cheese or Cheez Whiz for a more traditional Philly style"},{"original":"green bell peppers","swap":"poblano peppers or red bell peppers for a sweeter flavor"}]','["Using thick slices of steak instead of shaved or very thin slices which results in chewy meat","Skipping the step of toasting the hoagie rolls which leads to a soggy sandwich","Overcooking the vegetables until they are mushy rather than tender with some texture remaining"]','["sandwich","beef","Philly","cheesesteak","lunch","dinner","comfort food","game day"]','[]','Sandwiches','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Honey Garlic Glazed Salmon','honey-garlic-glazed-salmon','This honey garlic glazed salmon features a rich and sticky glaze that caramelizes beautifully over tender salmon fillets. The combination of sweet honey and savory garlic creates a bold and irresistible flavor profile that is ready in under 30 minutes.','A quick and flavorful salmon dish coated in a sweet and savory honey garlic glaze.','American','Easy',10,15,25,4,380,34,18,18,1,'[{"amount":4,"unit":"fillets","item":"salmon fillets","group":"Main"},{"amount":3,"unit":"tablespoons","item":"honey","group":"Glaze"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"Glaze"},{"amount":2,"unit":"tablespoons","item":"soy sauce","group":"Glaze"},{"amount":1,"unit":"tablespoon","item":"olive oil","group":"Cooking"},{"amount":1,"unit":"tablespoon","item":"lemon juice","group":"Glaze"},{"amount":0.5,"unit":"teaspoon","item":"black pepper","group":"Seasoning"},{"amount":0.5,"unit":"teaspoon","item":"salt","group":"Seasoning"}]','[{"title":"Prepare the Glaze","text":"In a small bowl, whisk together honey, minced garlic, soy sauce, and lemon juice until fully combined. Set aside for later use.","timer":0},{"title":"Season the Salmon","text":"Pat the salmon fillets dry with paper towels. Season both sides evenly with salt and black pepper to build a flavorful base.","timer":0},{"title":"Sear the Salmon","text":"Heat olive oil in a large skillet over medium high heat. Place the salmon fillets skin side up and sear for 4 minutes until a golden crust forms.","timer":240},{"title":"Apply the Glaze","text":"Flip the salmon fillets and pour the honey garlic glaze evenly over each fillet. Cook for another 4 to 5 minutes, spooning the glaze over the salmon repeatedly as it thickens.","timer":270},{"title":"Rest and Serve","text":"Remove the salmon from heat and let it rest for 2 minutes. Serve with your choice of steamed vegetables or rice, spooning any remaining glaze from the pan over the top.","timer":120}]','[{"original":"honey","swap":"maple syrup"},{"original":"soy sauce","swap":"coconut aminos"},{"original":"salmon fillets","swap":"trout fillets"}]','["Skipping the step of patting salmon dry which prevents proper searing and caramelization","Cooking on too low heat which steams the salmon instead of creating a caramelized crust","Flipping the salmon too early before a proper crust forms which causes the fish to tear"]','["salmon","honey garlic","glazed","seafood","quick dinner","weeknight meal","pan seared"]','["Gluten Free Option","Dairy Free","High Protein"]','Seafood','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Shrimp Scampi','shrimp-scampi','Shrimp scampi is a classic Italian American pasta dish featuring plump shrimp sauteed in a rich garlic butter and white wine sauce. This elegant yet simple recipe comes together in under 30 minutes and delivers restaurant quality flavor in every bite.','Tender shrimp tossed in a buttery garlic and white wine sauce served over linguine pasta.','Italian American','Easy',10,15,25,4,520,32,48,20,2,'[{"amount":1,"unit":"pound","item":"large shrimp peeled and deveined","group":"Main"},{"amount":12,"unit":"ounces","item":"linguine pasta","group":"Pasta"},{"amount":4,"unit":"tablespoons","item":"unsalted butter","group":"Sauce"},{"amount":5,"unit":"cloves","item":"garlic minced","group":"Sauce"},{"amount":0.5,"unit":"cup","item":"dry white wine","group":"Sauce"},{"amount":2,"unit":"tablespoons","item":"olive oil","group":"Cooking"},{"amount":2,"unit":"tablespoons","item":"fresh parsley chopped","group":"Garnish"},{"amount":0.5,"unit":"teaspoon","item":"red pepper flakes","group":"Seasoning"}]','[{"title":"Cook the Pasta","text":"Bring a large pot of salted water to a boil and cook linguine according to package directions until al dente. Reserve half a cup of pasta water before draining and set aside.","timer":480},{"title":"Saute the Garlic","text":"Heat olive oil and 2 tablespoons of butter in a large skillet over medium heat. Add the minced garlic and red pepper flakes and saute for about 1 minute until fragrant but do not allow the garlic to brown.","timer":60},{"title":"Cook the Shrimp","text":"Add the shrimp to the skillet in a single layer and cook for 2 minutes per side until they turn pink and curl into a C shape. Remove shrimp from the pan and set aside on a plate.","timer":240},{"title":"Build the Sauce","text":"Pour the white wine into the skillet and bring to a simmer, scraping up any browned bits from the bottom. Cook for 2 minutes until the wine reduces by half, then stir in the remaining butter until melted and glossy.","timer":120},{"title":"Combine and Serve","text":"Add the drained pasta and shrimp back into the skillet and toss everything together, adding reserved pasta water a little at a time to loosen the sauce. Garnish with fresh parsley and serve immediately.","timer":0}]','[{"original":"dry white wine","swap":"chicken broth with a squeeze of lemon"},{"original":"linguine pasta","swap":"angel hair pasta or spaghetti"},{"original":"unsalted butter","swap":"vegan butter for a dairy free version"}]','["Overcooking the shrimp past the point where they form an O shape which makes them rubbery and tough","Using pre cooked shrimp which results in a dry and chewy texture","Adding too much pasta water at once which makes the sauce watery instead of silky"]','["shrimp","pasta","scampi","Italian","garlic butter","seafood","quick dinner","white wine"]','["Dairy Free Option","High Protein"]','Seafood','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Air Fryer Coconut Shrimp','air-fryer-coconut-shrimp','These air fryer coconut shrimp deliver an incredibly crispy and golden coconut coating without the mess and extra calories of deep frying. Each bite offers a satisfying crunch followed by sweet coconut flavor that pairs perfectly with a tangy dipping sauce.','Crispy golden coconut shrimp made in the air fryer for a lighter and healthier take on a classic appetizer.','American','Easy',15,10,25,4,290,22,24,10,2,'[{"amount":1,"unit":"pound","item":"large shrimp peeled and deveined tails on","group":"Main"},{"amount":1,"unit":"cup","item":"shredded sweetened coconut","group":"Coating"},{"amount":0.5,"unit":"cup","item":"panko breadcrumbs","group":"Coating"},{"amount":0.5,"unit":"cup","item":"all purpose flour","group":"Coating"},{"amount":2,"unit":"large","item":"eggs beaten","group":"Coating"},{"amount":0.5,"unit":"teaspoon","item":"garlic powder","group":"Seasoning"},{"amount":0.5,"unit":"teaspoon","item":"salt","group":"Seasoning"},{"amount":1,"unit":"tablespoon","item":"cooking spray or oil spray","group":"Cooking"}]','[{"title":"Set Up the Breading Station","text":"Set up three shallow bowls in a row. Place flour seasoned with garlic powder and salt in the first bowl, beaten eggs in the second bowl, and a mixture of shredded coconut and panko breadcrumbs in the third bowl.","timer":0},{"title":"Bread the Shrimp","text":"Hold each shrimp by the tail and dredge it in the seasoned flour, shaking off any excess. Dip it into the beaten egg, allowing excess to drip off, then press it firmly into the coconut panko mixture to coat all sides evenly.","timer":0},{"title":"Preheat the Air Fryer","text":"Preheat your air fryer to 400 degrees Fahrenheit for 3 minutes. This step ensures even cooking and a crispier coating from the very start of the cook time.","timer":180},{"title":"Air Fry the Shrimp","text":"Arrange the breaded shrimp in a single layer in the air fryer basket without overlapping. Lightly spray the tops with cooking spray and cook for 5 minutes, then flip each shrimp, spray again, and cook for another 4 to 5 minutes until golden and crispy.","timer":600},{"title":"Serve with Dipping Sauce","text":"Remove the shrimp carefully from the air fryer and let them cool for 1 minute. Serve immediately with a sweet chili sauce or a mango dipping sauce on the side for the best flavor contrast.","timer":60}]','[{"original":"shredded sweetened coconut","swap":"unsweetened shredded coconut for a less sweet coating"},{"original":"all purpose flour","swap":"rice flour for a gluten free option"},{"original":"panko breadcrumbs","swap":"crushed cornflakes for extra crunch"}]','["Overcrowding the air fryer basket which causes the shrimp to steam instead of crisp up","Skipping the cooking spray which results in a dry and pale coconut coating that does not brown properly","Not pressing the coconut mixture firmly onto the shrimp which causes the coating to fall off during cooking"]','["shrimp","coconut shrimp","air fryer","appetizer","crispy","seafood","party food","gluten free option"]','["Dairy Free","High Protein","Gluten Free Option"]','Seafood','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Maryland Crab Cakes','maryland-crab-cakes','These classic Maryland crab cakes are packed with fresh lump crab meat and minimal filler to let the sweet crab flavor shine through. Seasoned with Old Bay and pan fried to golden perfection they are a true taste of the Chesapeake Bay.','Crispy golden crab cakes made with lump crab meat and Old Bay seasoning.','American','Medium',20,10,30,4,285,24,12,16,1,'[{"amount":1,"unit":"lb","item":"fresh lump crab meat","group":"main"},{"amount":0.33,"unit":"cup","item":"mayonnaise","group":"binder"},{"amount":1,"unit":"large","item":"egg beaten","group":"binder"},{"amount":2,"unit":"tsp","item":"Old Bay seasoning","group":"seasoning"},{"amount":1,"unit":"tsp","item":"Dijon mustard","group":"seasoning"},{"amount":1,"unit":"tsp","item":"Worcestershire sauce","group":"seasoning"},{"amount":0.5,"unit":"cup","item":"plain breadcrumbs","group":"binder"},{"amount":2,"unit":"tbsp","item":"unsalted butter","group":"cooking"}]','[{"title":"Prepare the crab mixture","text":"Pick through the crab meat carefully to remove any shells. In a large bowl combine mayonnaise, beaten egg, Old Bay seasoning, Dijon mustard and Worcestershire sauce and mix until smooth.","timer":0},{"title":"Fold in crab and breadcrumbs","text":"Gently fold the crab meat and breadcrumbs into the mayonnaise mixture. Do not overmix as you want to keep large chunks of crab intact for the best texture.","timer":0},{"title":"Form the crab cakes","text":"Divide the mixture into 8 equal portions and shape each into a round patty about 1 inch thick. Place the formed cakes on a lined baking sheet and refrigerate for at least 15 minutes to firm up.","timer":900},{"title":"Pan fry to golden","text":"Melt butter in a large skillet over medium high heat. Add crab cakes in batches and cook for 4 to 5 minutes per side until deep golden brown and heated through. Do not crowd the pan.","timer":600},{"title":"Serve immediately","text":"Transfer crab cakes to a paper towel lined plate to drain briefly. Serve hot with tartar sauce, lemon wedges or remoulade alongside a fresh green salad.","timer":0}]','[{"original":"plain breadcrumbs","swap":"crushed saltine crackers for a more traditional Maryland style"},{"original":"mayonnaise","swap":"Greek yogurt for a lighter lower fat version"},{"original":"unsalted butter","swap":"neutral oil such as avocado or vegetable oil for a dairy free option"}]','["Using too much filler like breadcrumbs which masks the crab flavor and produces a dense cake","Skipping the refrigeration step which causes the crab cakes to fall apart in the pan","Flipping the crab cakes too early before a proper crust has formed on the bottom"]','["seafood","crab","pan fried","Old Bay","Chesapeake","classic","appetizer","dinner"]','["pescatarian"]','Seafood','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Cajun Shrimp and Grits','cajun-shrimp-and-grits','This bold and comforting Southern dish features plump shrimp tossed in smoky Cajun spices served over a bed of rich and creamy stone ground grits. It is a satisfying one pan meal that brings the flavors of New Orleans straight to your kitchen.','Spicy Cajun shrimp served over creamy buttery stone ground grits.','Cajun','Medium',15,30,45,4,520,34,48,22,3,'[{"amount":1,"unit":"lb","item":"large shrimp peeled and deveined","group":"main"},{"amount":1,"unit":"cup","item":"stone ground grits","group":"base"},{"amount":2,"unit":"tbsp","item":"Cajun seasoning","group":"seasoning"},{"amount":4,"unit":"oz","item":"andouille sausage sliced","group":"main"},{"amount":1,"unit":"cup","item":"sharp cheddar cheese shredded","group":"grits"},{"amount":4,"unit":"tbsp","item":"unsalted butter divided","group":"cooking"},{"amount":3,"unit":"cloves","item":"garlic minced","group":"aromatics"},{"amount":0.5,"unit":"cup","item":"chicken broth","group":"sauce"}]','[{"title":"Cook the grits","text":"Bring 4 cups of water and a generous pinch of salt to a boil in a medium saucepan. Whisk in the stone ground grits and reduce heat to low. Cook stirring frequently for 20 to 25 minutes until thick and creamy then stir in 2 tablespoons of butter and all of the cheddar cheese.","timer":1500},{"title":"Season the shrimp","text":"Pat the shrimp dry with paper towels and toss them in a bowl with the Cajun seasoning until evenly coated. Make sure every piece is well covered for maximum flavor in the finished dish.","timer":0},{"title":"Brown the sausage","text":"Heat a large skillet over medium high heat and add the sliced andouille sausage. Cook for 3 to 4 minutes until browned and slightly crispy then remove and set aside leaving the rendered fat in the pan.","timer":240},{"title":"Cook the shrimp and sauce","text":"Add remaining butter to the same skillet and saute the garlic for 30 seconds until fragrant. Add the seasoned shrimp and cook for 2 minutes per side then pour in the chicken broth and return the sausage to the pan. Simmer for 2 minutes until the sauce thickens slightly.","timer":300},{"title":"Assemble and serve","text":"Spoon a generous portion of creamy cheddar grits into each bowl and top with the Cajun shrimp and sausage mixture. Drizzle any remaining pan sauce over the top and garnish with sliced green onions.","timer":0}]','[{"original":"stone ground grits","swap":"quick cooking grits to reduce the total cooking time significantly"},{"original":"andouille sausage","swap":"smoked kielbasa or chorizo for a similar smoky spicy flavor"},{"original":"sharp cheddar cheese","swap":"Gruyere or Parmesan for a different but equally rich cheesy result"}]','["Overcooking the shrimp until they become rubbery which happens very quickly so watch them closely","Not stirring the grits frequently enough which causes them to stick and burn on the bottom","Using instant grits instead of stone ground which results in a much less flavorful and textured base"]','["Cajun","Southern","shrimp","grits","spicy","comfort food","New Orleans","one pan","dinner"]','["gluten-free","pescatarian"]','Seafood','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Lobster Rolls','lobster-rolls','These classic New England lobster rolls are filled with chunks of sweet buttery lobster meat lightly dressed in a creamy lemony mayonnaise and served in a toasted split top bun. Simple and elegant they are the ultimate summer seafood sandwich that lets the lobster be the true star.','Sweet tender lobster tossed in lemon mayo and served in a toasted split top bun.','American','Medium',20,15,35,4,420,28,32,20,2,'[{"amount":2,"unit":"lb","item":"cooked lobster meat chopped into chunks","group":"main"},{"amount":0.33,"unit":"cup","item":"mayonnaise","group":"dressing"},{"amount":2,"unit":"tbsp","item":"fresh lemon juice","group":"dressing"},{"amount":2,"unit":"stalks","item":"celery finely diced","group":"dressing"},{"amount":1,"unit":"tbsp","item":"fresh chives chopped","group":"garnish"},{"amount":0.5,"unit":"tsp","item":"sea salt and black pepper to taste","group":"seasoning"},{"amount":4,"unit":"each","item":"split top hot dog buns","group":"base"},{"amount":3,"unit":"tbsp","item":"unsalted butter softened","group":"toasting"}]','[{"title":"Prepare the lobster filling","text":"If cooking whole lobsters boil them in salted water for 8 to 10 minutes then cool completely before removing the meat. Chop the lobster into generous bite sized chunks and place in a large mixing bowl.","timer":600},{"title":"Make the dressing","text":"In a small bowl whisk together mayonnaise, fresh lemon juice, salt and pepper until smooth and well combined. Taste and adjust the seasoning as needed before adding to the lobster.","timer":0},{"title":"Combine and chill","text":"Fold the diced celery and dressing gently into the lobster chunks being careful not to break up the meat too much. Add the chives and stir once more then refrigerate the mixture for at least 10 minutes to let the flavors meld.","timer":600},{"title":"Toast the buns","text":"Spread softened butter generously on the flat sides of each split top bun. Heat a large skillet or griddle over medium heat and toast the buns cut side down for 2 to 3 minutes until golden brown and crispy.","timer":180},{"title":"Fill and serve","text":"Spoon a generous and heaping portion of the chilled lobster salad into each toasted bun. Serve immediately with extra lemon wedges, kettle chips or a simple coleslaw on the side for a complete New England experience.","timer":0}]','[{"original":"mayonnaise","swap":"drawn butter instead of mayo for a Connecticut style warm buttered lobster roll"},{"original":"split top hot dog buns","swap":"brioche buns for a richer sweeter base that pairs beautifully with the lobster"},{"original":"fresh chives","swap":"fresh tarragon for a slightly more herbaceous and French inspired flavor profile"}]','["Overdressing the lobster with too much mayonnaise which overwhelms the delicate sweet flavor of the lobster","Using warm lobster straight from cooking without chilling which makes the dressing break down and become greasy","Skipping the toasting step on the buns which results in a soft soggy roll that cannot hold the filling properly"]','["lobster","New England","seafood","sandwich","summer","classic","comfort food","lunch","dinner"]','["pescatarian"]','Seafood','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('New York Cheesecake','new-york-cheesecake','This classic New York Cheesecake features a dense and creamy filling made with full-fat cream cheese on a buttery graham cracker crust. It is baked low and slow to achieve that signature smooth texture with no cracks.','A rich and creamy classic New York style cheesecake with a golden graham cracker crust.','American','Medium',30,70,100,12,480,8,38,34,1,'[{"amount":2,"unit":"cups","item":"graham cracker crumbs","group":"Crust"},{"amount":6,"unit":"tablespoons","item":"unsalted butter, melted","group":"Crust"},{"amount":32,"unit":"ounces","item":"full-fat cream cheese, softened","group":"Filling"},{"amount":1,"unit":"cup","item":"granulated sugar","group":"Filling"},{"amount":1,"unit":"cup","item":"sour cream","group":"Filling"},{"amount":3,"unit":"large","item":"eggs, room temperature","group":"Filling"},{"amount":2,"unit":"teaspoons","item":"pure vanilla extract","group":"Filling"},{"amount":2,"unit":"tablespoons","item":"all-purpose flour","group":"Filling"}]','[{"title":"Prepare the Crust","text":"Preheat your oven to 325 degrees F. Mix graham cracker crumbs with melted butter until the mixture resembles wet sand. Press firmly and evenly into the bottom of a 9-inch springform pan. Bake for 10 minutes then allow to cool completely.","timer":600},{"title":"Make the Filling","text":"Beat softened cream cheese and sugar together on medium speed until completely smooth and fluffy, about 3 minutes. Scrape down the sides of the bowl frequently to ensure no lumps remain. Add sour cream and vanilla extract and beat until just combined.","timer":180},{"title":"Add Eggs and Flour","text":"Add flour and mix on low speed until incorporated. Add eggs one at a time, beating on low speed after each addition just until the yellow disappears. Do not overmix once the eggs are added as this incorporates too much air into the batter.","timer":120},{"title":"Bake in Water Bath","text":"Wrap the outside of the springform pan tightly with two layers of heavy-duty aluminum foil. Pour the filling over the cooled crust and place the pan in a large roasting pan. Fill the roasting pan with hot water until it reaches halfway up the sides of the springform pan. Bake at 325 degrees F for 60 minutes until the edges are set but the center still jiggles slightly.","timer":3600},{"title":"Cool and Chill","text":"Turn off the oven and crack the door open slightly. Allow the cheesecake to cool inside the oven for 1 hour to prevent cracking from sudden temperature changes. Remove from the water bath, run a thin knife around the edges, and refrigerate uncovered for at least 6 hours or overnight before serving.","timer":3600}]','[{"original":"graham cracker crumbs","swap":"digestive biscuit crumbs or vanilla wafer crumbs"},{"original":"sour cream","swap":"full-fat Greek yogurt or creme fraiche"},{"original":"all-purpose flour","swap":"cornstarch for a gluten-free option"}]','["Using cold cream cheese which leads to a lumpy batter that will not bake smoothly","Overmixing the eggs which incorporates too much air and causes the cheesecake to crack and puff then sink","Skipping the water bath which results in uneven baking and a dry cracked surface"]','["cheesecake","new york","baked","classic","dessert","cream cheese","holiday","party"]','["Vegetarian"]','Dessert','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Lemon Curd Tart','lemon-curd-tart','This elegant Lemon Curd Tart features a crisp buttery shortcrust pastry shell filled with a silky smooth and vibrantly tangy lemon curd. It is the perfect balance of sweet and tart and makes a stunning centerpiece dessert for any occasion.','A bright and tangy lemon curd nestled in a crisp buttery pastry shell for an elegant dessert.','French','Medium',40,45,85,8,390,5,42,23,1,'[{"amount":1.5,"unit":"cups","item":"all-purpose flour","group":"Pastry"},{"amount":0.5,"unit":"cup","item":"unsalted butter, cold and cubed","group":"Pastry"},{"amount":0.25,"unit":"cup","item":"powdered sugar","group":"Pastry"},{"amount":4,"unit":"large","item":"eggs","group":"Lemon Curd"},{"amount":1,"unit":"cup","item":"granulated sugar","group":"Lemon Curd"},{"amount":0.5,"unit":"cup","item":"fresh lemon juice, about 4 lemons","group":"Lemon Curd"},{"amount":1,"unit":"tablespoon","item":"lemon zest","group":"Lemon Curd"},{"amount":0.5,"unit":"cup","item":"unsalted butter, cubed","group":"Lemon Curd"}]','[{"title":"Make the Shortcrust Pastry","text":"Combine flour and powdered sugar in a food processor. Add cold cubed butter and pulse until the mixture resembles fine breadcrumbs. Add one egg yolk and 2 tablespoons of ice cold water, pulsing until the dough just comes together. Flatten into a disc, wrap in plastic wrap, and refrigerate for 30 minutes.","timer":1800},{"title":"Blind Bake the Tart Shell","text":"Preheat the oven to 375 degrees F. Roll out the chilled pastry on a lightly floured surface and line a 9-inch tart pan with removable base. Trim the edges, prick the base all over with a fork, and line with parchment paper and baking weights. Bake for 15 minutes, remove the weights, and bake for another 10 minutes until golden.","timer":1500},{"title":"Prepare the Lemon Curd","text":"Whisk together the remaining 3 eggs plus 1 whole egg, granulated sugar, fresh lemon juice, and lemon zest in a medium saucepan over medium-low heat. Stir constantly with a wooden spoon or silicone spatula until the mixture thickens enough to coat the back of a spoon, about 10 minutes. Do not let the mixture boil.","timer":600},{"title":"Finish the Curd","text":"Remove the saucepan from the heat and strain the curd through a fine mesh sieve into a clean bowl to remove any cooked egg bits and zest. Add the cubed butter piece by piece, stirring until each piece is fully melted and incorporated. The curd should be glossy and smooth.","timer":300},{"title":"Fill and Set the Tart","text":"Pour the warm lemon curd into the cooled tart shell and spread it evenly with an offset spatula. Allow the tart to cool at room temperature for 30 minutes then refrigerate for at least 2 hours until the curd is fully set. Serve chilled garnished with fresh berries or whipped cream if desired.","timer":7200}]','[{"original":"fresh lemon juice","swap":"fresh lime juice or a combination of lemon and lime juice for a different citrus profile"},{"original":"all-purpose flour","swap":"gluten-free 1-to-1 baking flour for a gluten-free pastry shell"},{"original":"unsalted butter in curd","swap":"refined coconut oil for a dairy-free version of the lemon curd"}]','["Cooking the lemon curd over high heat which causes the eggs to scramble and creates a lumpy texture","Not blind baking the pastry shell which results in a soggy bottom that cannot hold the moist curd filling","Skipping the straining step which leaves bits of cooked egg and zest in the finished curd"]','["lemon","tart","curd","citrus","french","pastry","elegant","spring","summer"]','["Vegetarian"]','Dessert','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Creme Brulee','creme-brulee','This classic French Creme Brulee features a luxuriously rich and silky vanilla custard base topped with a perfectly caramelized sugar crust that shatters with a tap of a spoon. It is an elegant and impressive dessert that is simpler to make than most people expect.','A silky vanilla custard topped with a crackling caramelized sugar crust for a timeless French dessert.','French','Medium',20,45,65,6,420,5,28,33,0,'[{"amount":2,"unit":"cups","item":"heavy whipping cream","group":"Custard"},{"amount":1,"unit":"whole","item":"vanilla bean, split and scraped","group":"Custard"},{"amount":5,"unit":"large","item":"egg yolks","group":"Custard"},{"amount":0.5,"unit":"cup","item":"granulated sugar","group":"Custard"},{"amount":1,"unit":"pinch","item":"fine sea salt","group":"Custard"},{"amount":0.25,"unit":"cup","item":"granulated sugar, for topping","group":"Topping"},{"amount":1,"unit":"cup","item":"boiling water, for water bath","group":"Water Bath"},{"amount":1,"unit":"teaspoon","item":"pure vanilla extract, optional backup","group":"Custard"}]','[{"title":"Infuse the Cream","text":"Preheat your oven to 325 degrees F. Pour the heavy cream into a small saucepan and add the split vanilla bean pod along with its scraped seeds. Heat the cream over medium heat until it just begins to simmer around the edges, then remove from heat and let it steep for 15 minutes to infuse the vanilla flavor throughout.","timer":900},{"title":"Whisk the Egg Mixture","text":"In a large mixing bowl whisk together the egg yolks and granulated sugar until the mixture turns pale yellow and slightly thick, about 2 minutes. Add the pinch of sea salt and whisk to combine. Remove the vanilla bean pod from the cream and discard it.","timer":120},{"title":"Temper the Custard","text":"Slowly pour the warm infused cream into the egg yolk mixture in a thin steady stream while whisking constantly. This process of tempering gradually raises the temperature of the eggs without scrambling them. Skim off any foam that forms on the surface and strain the custard through a fine mesh sieve into a large measuring cup for easy pouring.","timer":180},{"title":"Bake the Custards","text":"Place 6 ramekins in a large roasting pan and divide the custard evenly among them. Carefully pour boiling water into the roasting pan until it reaches halfway up the sides of the ramekins. Cover the pan loosely with aluminum foil and bake at 325 degrees F for 40 to 45 minutes until the custards are set around the edges but still have a gentle wobble in the center like gelatin.","timer":2700},{"title":"Chill and Brulee","text":"Remove the ramekins from the water bath and allow them to cool at room temperature for 30 minutes. Refrigerate uncovered for at least 4 hours or overnight until fully chilled and set. When ready to serve, sprinkle an even thin layer of granulated sugar over each custard and use a kitchen torch to caramelize the sugar in circular motions until it forms a deep amber crackled crust. Serve immediately.","timer":14400}]','[{"original":"vanilla bean","swap":"1 teaspoon of pure vanilla extract or 1 teaspoon of vanilla bean paste"},{"original":"heavy whipping cream","swap":"half-and-half for a slightly lighter custard though the texture will be less rich"},{"original":"kitchen torch for brulee","swap":"place ramekins under a preheated broiler for 2 to 3 minutes watching closely to caramelize the sugar"}]','["Adding the hot cream too quickly to the egg yolks which scrambles the eggs and ruins the smooth custard base","Overbaking the custards until they are fully set and firm which results in a grainy rubbery texture instead of silky smoothness","Caramelizing the sugar too far in advance which causes the crust to absorb moisture from the custard and become soft and sticky"]','["creme brulee","french","custard","vanilla","classic","elegant","restaurant style","date night"]','["Vegetarian","Gluten-Free"]','Dessert','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Cinnamon Rolls','cinnamon-rolls','These soft and fluffy cinnamon rolls are filled with a rich buttery cinnamon sugar mixture and topped with a creamy vanilla glaze. They are perfect for weekend mornings or special occasions when you want to impress family and friends.','Soft homemade cinnamon rolls with buttery filling and sweet vanilla glaze.','American','Medium',90,25,115,12,380,6,58,14,2,'[{"amount":4,"unit":"cups","item":"all purpose flour","group":"Dough"},{"amount":2.25,"unit":"tsp","item":"active dry yeast","group":"Dough"},{"amount":1,"unit":"cup","item":"warm milk","group":"Dough"},{"amount":0.33,"unit":"cup","item":"unsalted butter softened","group":"Dough"},{"amount":3,"unit":"tbsp","item":"granulated sugar","group":"Dough"},{"amount":2,"unit":"tbsp","item":"ground cinnamon","group":"Filling"},{"amount":0.75,"unit":"cup","item":"packed brown sugar","group":"Filling"},{"amount":1.5,"unit":"cups","item":"powdered sugar","group":"Glaze"}]','[{"title":"Activate the Yeast","text":"Combine warm milk and granulated sugar in a large bowl then sprinkle yeast over the top. Let it sit for 5 to 10 minutes until foamy and fragrant. This confirms your yeast is active and your rolls will rise properly.","timer":600},{"title":"Make the Dough","text":"Add softened butter and flour to the yeast mixture and mix until a soft dough forms. Knead the dough on a lightly floured surface for about 8 minutes until it is smooth and elastic. Place the dough in a greased bowl, cover with a clean towel, and let it rise for 1 hour until doubled in size.","timer":3600},{"title":"Add the Filling","text":"Roll the risen dough out into a large rectangle about 12 by 18 inches on a floured surface. Spread softened butter evenly over the surface then sprinkle the brown sugar and cinnamon mixture all over the dough. Roll the dough tightly from the long edge into a log shape.","timer":300},{"title":"Cut and Rise","text":"Slice the log into 12 equal rolls using a sharp knife or unflavored dental floss for clean cuts. Place the rolls cut side up in a greased baking dish and cover loosely. Allow them to rise for another 30 minutes until they are puffy and touching each other.","timer":1800},{"title":"Bake and Glaze","text":"Bake the rolls in a preheated oven at 375 degrees Fahrenheit for 22 to 25 minutes until golden brown on top. While they cool slightly, whisk powdered sugar with 2 to 3 tablespoons of milk until smooth. Drizzle the glaze generously over the warm rolls and serve immediately.","timer":1500}]','[{"original":"whole milk","swap":"oat milk or almond milk for a dairy free version"},{"original":"unsalted butter in filling","swap":"coconut oil for a dairy free alternative"},{"original":"all purpose flour","swap":"bread flour for a chewier and more structured roll"}]','["Using milk that is too hot which kills the yeast and prevents the dough from rising","Not kneading the dough long enough which results in dense and tough rolls","Skipping the second rise which causes the rolls to be flat and dry after baking"]','["breakfast","brunch","baking","comfort food","sweet","homemade","holiday"]','["vegetarian"]','Breakfast','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Banana Bread Chocolate Chips','banana-bread-chocolate-chips','This moist and tender banana bread is loaded with rich chocolate chips in every bite making it an irresistible treat for chocolate and banana lovers alike. The riper the bananas you use the sweeter and more flavorful your loaf will turn out.','Moist banana bread packed with melty chocolate chips for the ultimate sweet treat.','American','Easy',15,60,75,10,310,5,44,13,2,'[{"amount":3,"unit":"whole","item":"very ripe bananas mashed","group":"Wet Ingredients"},{"amount":2,"unit":"whole","item":"large eggs","group":"Wet Ingredients"},{"amount":0.5,"unit":"cup","item":"unsalted butter melted","group":"Wet Ingredients"},{"amount":0.75,"unit":"cup","item":"granulated sugar","group":"Wet Ingredients"},{"amount":1.5,"unit":"cups","item":"all purpose flour","group":"Dry Ingredients"},{"amount":1,"unit":"tsp","item":"baking soda","group":"Dry Ingredients"},{"amount":0.5,"unit":"tsp","item":"salt","group":"Dry Ingredients"},{"amount":1,"unit":"cup","item":"semi sweet chocolate chips","group":"Mix In"}]','[{"title":"Prepare Your Pan and Oven","text":"Preheat your oven to 350 degrees Fahrenheit and grease a 9 by 5 inch loaf pan with butter or nonstick spray. You can also line the pan with parchment paper leaving some overhang on the sides for easy removal. This step ensures the bread does not stick and comes out cleanly every time.","timer":300},{"title":"Mash Bananas and Mix Wet Ingredients","text":"Peel the ripe bananas and mash them thoroughly in a large mixing bowl using a fork until nearly smooth with just a few small lumps remaining. Add the melted butter, sugar, and eggs to the mashed bananas and stir everything together until well combined and uniform.","timer":300},{"title":"Combine Dry Ingredients","text":"In a separate bowl whisk together the flour, baking soda, and salt until evenly distributed. Gently fold the dry ingredients into the wet banana mixture using a spatula and stir only until just combined. Do not overmix the batter as this will make the bread tough and dense.","timer":180},{"title":"Fold in Chocolate Chips","text":"Reserve about 2 tablespoons of chocolate chips for topping the loaf then fold the remaining chips into the batter with a gentle hand. Pour the batter into the prepared loaf pan and spread it evenly with the spatula. Scatter the reserved chocolate chips across the top of the batter.","timer":120},{"title":"Bake and Cool","text":"Bake the loaf for 55 to 65 minutes until a toothpick inserted into the center comes out clean with no wet batter clinging to it. If the top is browning too quickly cover it loosely with aluminum foil for the last 15 minutes. Let the bread cool in the pan for 10 minutes before transferring to a wire rack.","timer":3600}]','[{"original":"unsalted butter","swap":"coconut oil or vegetable oil for a dairy free loaf"},{"original":"granulated sugar","swap":"honey or maple syrup reducing amount to half a cup for natural sweetness"},{"original":"semi sweet chocolate chips","swap":"dark chocolate chunks or white chocolate chips for a flavor variation"}]','["Using underripe bananas that are not sweet enough resulting in a bland and dry loaf","Overmixing the batter after adding flour which develops gluten and creates a tough texture","Removing the bread from the oven too early before the center is fully set leading to a gummy middle"]','["breakfast","snack","baking","chocolate","banana","quick bread","easy"]','["vegetarian"]','Baked Goods','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Carrot Cake','carrot-cake','This classic carrot cake is incredibly moist and warmly spiced with cinnamon and nutmeg then topped with a luxuriously smooth cream cheese frosting. Every slice is packed with freshly grated carrots that add natural sweetness and a wonderfully tender crumb.','Moist spiced carrot cake with lush cream cheese frosting that is perfect for any celebration.','American','Medium',30,35,65,12,480,6,62,24,2,'[{"amount":2,"unit":"cups","item":"all purpose flour","group":"Dry Ingredients"},{"amount":2,"unit":"tsp","item":"ground cinnamon","group":"Dry Ingredients"},{"amount":1,"unit":"tsp","item":"baking soda","group":"Dry Ingredients"},{"amount":3,"unit":"whole","item":"large eggs","group":"Wet Ingredients"},{"amount":1,"unit":"cup","item":"vegetable oil","group":"Wet Ingredients"},{"amount":1.5,"unit":"cups","item":"granulated sugar","group":"Wet Ingredients"},{"amount":2.5,"unit":"cups","item":"freshly grated carrots","group":"Wet Ingredients"},{"amount":8,"unit":"oz","item":"full fat cream cheese softened","group":"Frosting"}]','[{"title":"Prepare Pans and Preheat Oven","text":"Preheat the oven to 350 degrees Fahrenheit and grease two 9 inch round cake pans then line the bottoms with parchment paper circles. Lightly flour the sides of the pans after greasing to prevent any sticking during baking. Having your pans ready before mixing the batter ensures you can move quickly once everything is combined.","timer":300},{"title":"Mix the Dry Ingredients","text":"In a large bowl whisk together the flour, ground cinnamon, baking soda, and a half teaspoon of salt until evenly combined. Whisking the dry ingredients together first ensures the spices and leavening agents are distributed evenly throughout the batter. Set this bowl aside while you prepare the wet ingredients.","timer":120},{"title":"Combine Wet Ingredients and Carrots","text":"In another large bowl beat the eggs, vegetable oil, and granulated sugar together vigorously until the mixture is pale and slightly thickened. Fold in the freshly grated carrots and stir until they are fully incorporated into the wet mixture. Then gently fold the dry ingredients into the wet ingredients until just combined with no streaks of flour remaining.","timer":300},{"title":"Bake the Cake Layers","text":"Divide the batter evenly between the two prepared cake pans and smooth the tops with a spatula. Bake for 30 to 35 minutes until the tops spring back when lightly pressed and a toothpick inserted into the center comes out clean. Allow the cakes to cool in their pans for 15 minutes before turning them out onto wire racks to cool completely.","timer":2100},{"title":"Make Frosting and Assemble","text":"Beat the softened cream cheese with half a cup of softened butter until smooth and fluffy then gradually add 3 cups of powdered sugar and 1 teaspoon of vanilla extract. Beat the frosting until it is light and spreadable with no lumps remaining. Place one cooled cake layer on a serving plate, spread a thick layer of frosting on top, place the second layer over it, then frost the top and sides of the entire cake.","timer":600}]','[{"original":"vegetable oil","swap":"melted coconut oil for a subtle coconut flavor and slightly denser crumb"},{"original":"full fat cream cheese","swap":"dairy free cream cheese for a lactose free frosting option"},{"original":"granulated sugar","swap":"coconut sugar for a deeper caramel like sweetness throughout the cake"}]','["Using pre shredded store bought carrots that are too dry and coarse leading to a less moist cake","Frosting the cake before the layers are completely cooled which causes the frosting to melt and slide off","Overmixing the batter once the flour is added which results in a tough and dense cake texture"]','["cake","dessert","baking","celebration","cream cheese frosting","spiced","classic"]','["vegetarian"]','Dessert','ai');